{
  "name": "DebtChaser",
  "description": "Professional debt recovery and invoice tracking tool with automated WhatsApp reminder simulations to help small businesses get paid faster."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

// Mock storage implementation as expected by the provided code
const storage = {
  get: async (key: string) => {
    const val = localStorage.getItem(key);
    return val ? { value: val } : null;
  },
  set: async (key: string, value: string) => {
    localStorage.setItem(key, value);
  },
  delete: async (key: string) => {
    localStorage.removeItem(key);
  }
};

(window as any).storage = storage;

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type InvoiceStatus = 'overdue' | 'pending' | 'upcoming' | 'paid' | 'disputed';
export type MessageTone = 'friendly' | 'firm' | 'urgent' | 'final' | 'balanced';

export interface Message {
  date: string;
  type: MessageTone;
  sent: boolean;
}

export interface Invoice {
  id: number;
  clientName: string;
  amount: number;
  dueDate: string;
  clientPhone: string;
  invoiceNumber: string;
  status: InvoiceStatus;
  remindersSent: number;
  messages: Message[];
  createdAt: string;
  paidDate?: string;
  paidAmount?: number;
  paymentMethod?: string;
  paymentNotes?: string;
}

export interface Settings {
  businessName: string;
  messageStyle: string;
  firstReminderDays: number;
  escalationDays: number;
  workingHoursOnly: boolean;
  pauseWeekends: boolean;
  whatsappConnected: boolean;
}

export interface TeamMember {
  id: number;
  name: string;
  email: string;
  role: string;
  avatar: string;
}

export interface Analytics {
  totalRecovered: number;
  totalOutstanding: number;
  overdueAmount: number;
  thisMonthRecovered: number;
  averageDaysToPayment: number;
  successRate: number;
}

import React, { useState, useEffect, useCallback } from 'react';
import { 
  DollarSign, Clock, CheckCircle, AlertCircle, Send, Plus, ArrowLeft, 
  Calendar, User, FileText, MessageSquare, Camera, X, Check, Settings as SettingsIcon, 
  CreditCard, PauseCircle, Edit3, Bell, Smartphone, Building, Share2, Mail, 
  Download, ChevronRight, Zap, Shield, TrendingUp, Users, Link2, QrCode, 
  PhoneCall, BarChart3, TrendingDown, Copy, CheckCheck, Wifi, WifiOff, Trash2 
} from 'lucide-react';
import { 
  Invoice, Message, Settings, TeamMember, Analytics, 
  InvoiceStatus, MessageTone 
} from './types';

// Helper for storage types
interface StorageResult {
  value: string;
}

const messageTemplates: Record<string, { title: string; example: string }> = {
  friendly: {
    title: "Friendly Reminder",
    example: "Hi {name}! 👋 Just a gentle reminder that invoice #{number} for R{amount} was due on {date}. When can we expect payment? Let me know if you need the invoice resent. Thanks!"
  },
  firm: {
    title: "Firm Follow-up",
    example: "Hi {name}, invoice #{number} for R{amount} is now {days} days overdue. Please arrange payment this week. If there's an issue, let's discuss. Payment details attached."
  },
  urgent: {
    title: "Urgent Notice",
    example: "{name}, invoice #{number} (R{amount}) remains unpaid after {days} days. This is affecting our cashflow. Please prioritize payment immediately or contact me today to arrange a plan."
  },
  final: {
    title: "Final Notice",
    example: "{name}, FINAL NOTICE: Invoice #{number} for R{amount} is {days} days overdue. Payment must be received within 48 hours to avoid further action. Contact me urgently if there are any issues."
  }
};

export default function DebtChaser() {
  const [loading, setLoading] = useState(true);
  const [selectedInvoiceId, setSelectedInvoiceId] = useState<number | null>(null);
  const [showUpload, setShowUpload] = useState(false);
  const [showSendConfirm, setShowSendConfirm] = useState(false);
  const [showPaymentLog, setShowPaymentLog] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [showQRModal, setShowQRModal] = useState(false);
  const [shareStep, setShareStep] = useState<'options' | 'whatsapp' | 'link'>('options');
  const [copiedLink, setCopiedLink] = useState(false);
  const [hasSeenOnboarding, setHasSeenOnboarding] = useState(false);

  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [settings, setSettings] = useState<Settings>({
    businessName: "Your Business",
    messageStyle: "balanced",
    firstReminderDays: 2,
    escalationDays: 3,
    workingHoursOnly: true,
    pauseWeekends: false,
    whatsappConnected: true
  });
  const [teamMembers, setTeamMembers] = useState<TeamMember[]>([]);

  const loadData = useCallback(async () => {
    try {
      const storage = (window as any).storage;

      // Load invoices
      const invoicesResult: StorageResult | null = await storage.get('invoices');
      if (invoicesResult) {
        setInvoices(JSON.parse(invoicesResult.value));
      }

      // Load settings
      const settingsResult: StorageResult | null = await storage.get('settings');
      if (settingsResult) {
        setSettings(JSON.parse(settingsResult.value));
      }

      // Load team members
      const teamResult: StorageResult | null = await storage.get('team');
      if (teamResult) {
        setTeamMembers(JSON.parse(teamResult.value));
      } else {
        const defaultTeam = [
          { id: 1, name: "You", email: "you@business.com", role: "owner", avatar: "Y" }
        ];
        setTeamMembers(defaultTeam);
        await storage.set('team', JSON.stringify(defaultTeam));
      }

      // Check onboarding
      const onboardingResult = await storage.get('onboarding_complete');
      setHasSeenOnboarding(!!onboardingResult);

    } catch (error) {
      console.error('Initialization error:', error);
      setInvoices([]);
      setTeamMembers([{ id: 1, name: "You", email: "you@business.com", role: "owner", avatar: "Y" }]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const saveInvoices = async (newInvoices: Invoice[]) => {
    setInvoices(newInvoices);
    await (window as any).storage.set('invoices', JSON.stringify(newInvoices));
  };

  const saveSettings = async (newSettings: Settings) => {
    setSettings(newSettings);
    await (window as any).storage.set('settings', JSON.stringify(newSettings));
  };

  const getInvoiceStatus = (dueDate: string): InvoiceStatus => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const due = new Date(dueDate);
    due.setHours(0, 0, 0, 0);

    const diffTime = due.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return 'overdue';
    if (diffDays <= 3) return 'pending';
    return 'upcoming';
  };

  const getDaysOverdue = (dueDate: string) => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const due = new Date(dueDate);
    due.setHours(0, 0, 0, 0);

    const diffTime = today.getTime() - due.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    return diffDays > 0 ? diffDays : 0;
  };

  const addInvoice = async (invoiceData: Partial<Invoice>) => {
    const newInvoice: Invoice = {
      id: Date.now(),
      clientName: invoiceData.clientName || '',
      amount: invoiceData.amount || 0,
      dueDate: invoiceData.dueDate || '',
      clientPhone: invoiceData.clientPhone || '',
      invoiceNumber: invoiceData.invoiceNumber || '',
      status: getInvoiceStatus(invoiceData.dueDate || ''),
      remindersSent: 0,
      messages: [],
      createdAt: new Date().toISOString()
    };

    const updated = [...invoices, newInvoice];
    await saveInvoices(updated);
    return newInvoice;
  };

  const updateInvoice = async (id: number, updates: Partial<Invoice>) => {
    const updated = invoices.map(inv => 
      inv.id === id ? { ...inv, ...updates } : inv
    );
    await saveInvoices(updated);
  };

  const deleteInvoice = async (id: number) => {
    const updated = invoices.filter(inv => inv.id !== id);
    await saveInvoices(updated);
  };

  const markAsPaid = async (id: number, paymentData: { date: string; amount: number; method: string; notes: string }) => {
    await updateInvoice(id, {
      status: 'paid',
      paidDate: paymentData.date,
      paidAmount: paymentData.amount,
      paymentMethod: paymentData.method,
      paymentNotes: paymentData.notes
    });
  };

  const sendReminder = async (id: number, messageType: MessageTone) => {
    const invoice = invoices.find(inv => inv.id === id);
    if (!invoice) return;

    const newMessage: Message = {
      date: new Date().toISOString(),
      type: messageType,
      sent: true
    };

    await updateInvoice(id, {
      messages: [...invoice.messages, newMessage],
      remindersSent: invoice.remindersSent + 1,
      lastReminder: new Date().toISOString() as any
    });
  };

  const analytics: Analytics = {
    totalRecovered: invoices.filter(inv => inv.status === 'paid').reduce((sum, inv) => sum + (inv.paidAmount || inv.amount), 0),
    totalOutstanding: invoices.filter(inv => inv.status !== 'paid').reduce((sum, inv) => sum + inv.amount, 0),
    overdueAmount: invoices.filter(inv => inv.status === 'overdue').reduce((sum, inv) => sum + inv.amount, 0),
    thisMonthRecovered: invoices.filter(inv => {
      if (inv.status !== 'paid' || !inv.paidDate) return false;
      const paidDate = new Date(inv.paidDate);
      const now = new Date();
      return paidDate.getMonth() === now.getMonth() && paidDate.getFullYear() === now.getFullYear();
    }).reduce((sum, inv) => sum + (inv.paidAmount || inv.amount), 0),
    averageDaysToPayment: (() => {
      const paidInvoices = invoices.filter(inv => inv.status === 'paid' && inv.paidDate);
      if (paidInvoices.length === 0) return 0;
      const totalDays = paidInvoices.reduce((sum, inv) => {
        const due = new Date(inv.dueDate);
        const paid = new Date(inv.paidDate!);
        const days = Math.ceil((paid.getTime() - due.getTime()) / (1000 * 60 * 60 * 24));
        return sum + days;
      }, 0);
      return Math.round(totalDays / paidInvoices.length);
    })(),
    successRate: invoices.length > 0 ? Math.round((invoices.filter(inv => inv.status === 'paid').length / invoices.length) * 100) : 0
  };

  const getStatusColor = (status: InvoiceStatus) => {
    switch(status) {
      case 'overdue': return 'text-red-600 bg-red-50';
      case 'pending': return 'text-amber-600 bg-amber-50';
      case 'upcoming': return 'text-blue-600 bg-blue-50';
      case 'paid': return 'text-emerald-600 bg-emerald-50';
      case 'disputed': return 'text-purple-600 bg-purple-50';
      default: return 'text-gray-600 bg-gray-50';
    }
  };

  const getStatusIcon = (status: InvoiceStatus) => {
    switch(status) {
      case 'overdue': return AlertCircle;
      case 'pending': return Clock;
      case 'upcoming': return Calendar;
      case 'paid': return CheckCircle;
      case 'disputed': return PauseCircle;
      default: return FileText;
    }
  };

  const formatMessage = (template: string, invoice: Invoice) => {
    const daysOverdue = getDaysOverdue(invoice.dueDate);
    return template
      .replace('{name}', invoice.clientName.split("'")[0])
      .replace('{number}', invoice.invoiceNumber || `${invoice.id}`)
      .replace('{amount}', invoice.amount.toLocaleString())
      .replace('{date}', new Date(invoice.dueDate).toLocaleDateString('en-ZA'))
      .replace('{days}', daysOverdue.toString());
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopiedLink(true);
    setTimeout(() => setCopiedLink(false), 2000);
  };

  // Sub-components as per guidance (outside main body or defined clearly)

  const WhatsAppMessage: React.FC<{ message: string; sent?: boolean }> = ({ message, sent = true }) => (
    <div className={`flex ${sent ? 'justify-end' : 'justify-start'} mb-2`}>
      <div className={`max-w-[85%] rounded-lg px-4 py-2.5 ${
        sent ? 'bg-[#DCF8C6] text-gray-900' : 'bg-white text-gray-900 border'
      }`}>
        <p className="text-[15px] leading-relaxed whitespace-pre-wrap">{message}</p>
        <div className="flex items-center justify-end gap-1 mt-1">
          <span className="text-[11px] text-gray-500">
            {new Date().toLocaleTimeString('en-ZA', { hour: '2-digit', minute: '2-digit' })}
          </span>
          {sent && <Check className="w-4 h-4 text-blue-600" />}
        </div>
      </div>
    </div>
  );

  const OnboardingFlow = () => {
    const [step, setStep] = useState(0);
    const steps = [
      {
        title: "Welcome to Debt Chaser",
        subtitle: "Stop chasing. Start collecting.",
        description: "Automated WhatsApp reminders that get you paid faster - without the awkward phone calls.",
        icon: Zap,
        color: "blue"
      },
      {
        title: "How It Works",
        subtitle: "Three simple steps",
        steps: [
          { icon: Camera, text: "Upload your invoice (photo or WhatsApp)" },
          { icon: Send, text: "We send professional reminders automatically" },
          { icon: CheckCircle, text: "You get paid, we track everything" }
        ],
        icon: TrendingUp,
        color: "emerald"
      },
      {
        title: "You're In Control",
        subtitle: "Full transparency, no surprises",
        description: "Preview every message before it sends. Change the tone. Pause anytime. Your business, your rules.",
        icon: Shield,
        color: "purple"
      }
    ];

    const currentStep = steps[step];
    const isLastStep = step === steps.length - 1;

    return (
      <div className="fixed inset-0 bg-gradient-to-br from-blue-600 to-blue-800 z-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl w-full max-w-md overflow-hidden shadow-2xl">
          <div className="p-8 text-center">
            <div className={`inline-flex items-center justify-center w-20 h-20 rounded-full mb-6 ${
              currentStep.color === 'blue' ? 'bg-blue-100' :
              currentStep.color === 'emerald' ? 'bg-emerald-100' :
              'bg-purple-100'
            }`}>
              <currentStep.icon className={`w-10 h-10 ${
                currentStep.color === 'blue' ? 'text-blue-600' :
                currentStep.color === 'emerald' ? 'text-emerald-600' :
                'text-purple-600'
              }`} />
            </div>
            <h2 className="text-2xl font-bold text-gray-900 mb-2">{currentStep.title}</h2>
            <p className="text-lg text-gray-600 mb-6">{currentStep.subtitle}</p>
            {currentStep.description && (
              <p className="text-gray-700 leading-relaxed mb-6">{currentStep.description}</p>
            )}
            {currentStep.steps && (
              <div className="space-y-4 mb-6 text-left">
                {currentStep.steps.map((s, idx) => (
                  <div key={idx} className="flex items-start gap-4 p-4 bg-gray-50 rounded-lg">
                    <div className="flex-shrink-0 w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-sm">
                      <s.icon className="w-5 h-5 text-emerald-600" />
                    </div>
                    <p className="text-gray-700 pt-2">{s.text}</p>
                  </div>
                ))}
              </div>
            )}
            <div className="flex items-center justify-center gap-2 mb-6">
              {steps.map((_, idx) => (
                <div key={idx} className={`h-2 rounded-full transition-all ${idx === step ? 'w-8 bg-blue-600' : 'w-2 bg-gray-300'}`} />
              ))}
            </div>
            <div className="flex gap-3">
              {step > 0 && (
                <button onClick={() => setStep(step - 1)} className="flex-1 border border-gray-300 text-gray-700 py-3 rounded-lg font-medium hover:bg-gray-50 transition-colors">
                  Back
                </button>
              )}
              <button
                onClick={async () => {
                  if (isLastStep) {
                    await (window as any).storage.set('onboarding_complete', 'true');
                    setHasSeenOnboarding(true);
                    setShowUpload(true);
                  } else {
                    setStep(step + 1);
                  }
                }}
                className={`${step === 0 ? 'w-full' : 'flex-1'} bg-blue-600 text-white py-3 rounded-lg font-medium hover:bg-blue-700 transition-colors flex items-center justify-center gap-2`}
              >
                {isLastStep ? 'Add My First Invoice' : 'Continue'}
                <ChevronRight className="w-5 h-5" />
              </button>
            </div>
            <button
              onClick={async () => {
                await (window as any).storage.set('onboarding_complete', 'true');
                setHasSeenOnboarding(true);
              }}
              className="mt-4 text-sm text-gray-500 hover:text-gray-700"
            >
              Skip for now
            </button>
          </div>
        </div>
      </div>
    );
  };

  const UploadFlow = () => {
    const [formData, setFormData] = useState({
      clientName: '',
      amount: '',
      dueDate: '',
      clientPhone: '',
      invoiceNumber: ''
    });

    const handleSubmit = async () => {
      await addInvoice({
        clientName: formData.clientName,
        amount: parseFloat(formData.amount),
        dueDate: formData.dueDate,
        clientPhone: formData.clientPhone,
        invoiceNumber: formData.invoiceNumber
      });
      setShowUpload(false);
    };

    return (
      <div className="min-h-screen bg-gray-50 pb-20">
        <div className="bg-white border-b sticky top-0 z-10">
          <div className="max-w-2xl mx-auto px-4 py-4 flex items-center gap-3">
            <button onClick={() => setShowUpload(false)} className="p-2 hover:bg-gray-100 rounded-lg">
              <ArrowLeft className="w-5 h-5" />
            </button>
            <h1 className="text-lg font-semibold">Add New Invoice</h1>
          </div>
        </div>
        <div className="max-w-2xl mx-auto px-4 py-6 space-y-6">
          <div className="bg-white rounded-lg border p-6 space-y-5">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Client Name *</label>
              <input type="text" value={formData.clientName} onChange={(e) => setFormData({...formData, clientName: e.target.value})} placeholder="e.g. Thabo's Hardware" className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Invoice Amount (R) *</label>
              <input type="number" value={formData.amount} onChange={(e) => setFormData({...formData, amount: e.target.value})} placeholder="4500" className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Due Date *</label>
              <input type="date" value={formData.dueDate} onChange={(e) => setFormData({...formData, dueDate: e.target.value})} className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Client WhatsApp Number *</label>
              <input type="tel" value={formData.clientPhone} onChange={(e) => setFormData({...formData, clientPhone: e.target.value})} placeholder="+27 XX XXX XXXX" className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Invoice Number (Optional)</label>
              <input type="text" value={formData.invoiceNumber} onChange={(e) => setFormData({...formData, invoiceNumber: e.target.value})} placeholder="INV-001" className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500" />
            </div>
          </div>
          <button 
            onClick={handleSubmit} 
            disabled={!formData.clientName || !formData.amount || !formData.dueDate || !formData.clientPhone}
            className="w-full bg-blue-600 text-white py-4 rounded-lg font-semibold hover:bg-blue-700 transition-colors disabled:bg-gray-300"
          >
            Add Invoice
          </button>
        </div>
      </div>
    );
  };

  const InvoiceDetail = () => {
    const invoice = invoices.find(inv => inv.id === selectedInvoiceId);
    if (!invoice) return null;
    const StatusIcon = getStatusIcon(invoice.status);
    const daysOverdue = getDaysOverdue(invoice.dueDate);

    return (
      <div className="min-h-screen bg-gray-50 pb-20">
        <div className="bg-white border-b sticky top-0 z-10">
          <div className="max-w-2xl mx-auto px-4 py-4 flex items-center gap-3">
            <button onClick={() => setSelectedInvoiceId(null)} className="p-2 hover:bg-gray-100 rounded-lg">
              <ArrowLeft className="w-5 h-5" />
            </button>
            <div className="flex-1">
              <h1 className="text-lg font-semibold">{invoice.clientName}</h1>
              <p className="text-sm text-gray-500">Invoice {invoice.invoiceNumber || invoice.id}</p>
            </div>
            <button onClick={() => setShowQRModal(true)} className="p-2 hover:bg-gray-100 rounded-lg"><QrCode className="w-5 h-5" /></button>
            <button onClick={() => setShowShareModal(true)} className="p-2 hover:bg-gray-100 rounded-lg"><Share2 className="w-5 h-5" /></button>
            <button onClick={async () => { if(confirm('Delete?')) { await deleteInvoice(invoice.id); setSelectedInvoiceId(null); }}} className="p-2 hover:bg-gray-100 rounded-lg"><Trash2 className="w-5 h-5 text-red-600" /></button>
          </div>
        </div>
        <div className="max-w-2xl mx-auto px-4 py-6 space-y-6">
          <div className="bg-white rounded-lg border p-6">
            <div className="flex items-start justify-between mb-4">
              <div>
                <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-sm font-medium ${getStatusColor(invoice.status)}`}>
                  <StatusIcon className="w-4 h-4" />
                  {invoice.status === 'overdue' ? `${daysOverdue}d overdue` : invoice.status}
                </span>
                <p className="text-3xl font-bold text-gray-900 mt-2">R{invoice.amount.toLocaleString()}</p>
              </div>
            </div>
            <div className="space-y-2 text-sm border-t pt-4">
              <div className="flex justify-between"><span className="text-gray-600">Due date</span><span className="font-medium">{new Date(invoice.dueDate).toLocaleDateString('en-ZA')}</span></div>
              <div className="flex justify-between"><span className="text-gray-600">Client phone</span><span className="font-medium">{invoice.clientPhone}</span></div>
              {invoice.status === 'paid' && <div className="flex justify-between"><span className="text-gray-600">Paid date</span><span className="font-medium text-emerald-600">{new Date(invoice.paidDate!).toLocaleDateString('en-ZA')}</span></div>}
              <div className="flex justify-between"><span className="text-gray-600">Reminders sent</span><span className="font-medium">{invoice.remindersSent}</span></div>
            </div>
          </div>
          <div className="bg-white rounded-lg border">
            <div className="px-6 py-4 border-b"><h2 className="font-semibold">Message History</h2></div>
            <div className="p-6 space-y-4">
              {invoice.messages.length === 0 ? <p className="text-center text-gray-500 py-8">No messages sent yet</p> : 
                invoice.messages.map((msg, idx) => (
                  <div key={idx} className="border rounded-lg overflow-hidden">
                    <div className="flex items-center justify-between px-4 py-2 bg-gray-50 border-b">
                      <span className="text-xs font-semibold uppercase">{msg.type}</span>
                      <span className="text-xs text-gray-500">{new Date(msg.date).toLocaleDateString('en-ZA')}</span>
                    </div>
                    <div className="bg-[#ECE5DD] p-4"><WhatsAppMessage message={formatMessage(messageTemplates[msg.type].example, invoice)} /></div>
                  </div>
              ))}
            </div>
          </div>
          {invoice.status !== 'paid' && (
            <div className="space-y-3">
              <button onClick={() => setShowSendConfirm(true)} className="w-full bg-[#25D366] text-white py-3 rounded-lg font-medium flex items-center justify-center gap-2"><Send className="w-4 h-4" /> Send Reminder</button>
              <button onClick={() => setShowPaymentLog(true)} className="w-full border border-emerald-600 text-emerald-600 py-3 rounded-lg font-medium flex items-center justify-center gap-2"><CheckCircle className="w-4 h-4" /> Mark as Paid</button>
            </div>
          )}
        </div>
      </div>
    );
  };

  if (loading) return <div className="min-h-screen bg-gray-50 flex items-center justify-center animate-pulse">Loading...</div>;
  if (!hasSeenOnboarding) return <OnboardingFlow />;
  if (showUpload) return <UploadFlow />;
  if (selectedInvoiceId) return <><InvoiceDetail />
    {showSendConfirm && (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-end sm:items-center justify-center p-4">
        <div className="bg-white rounded-t-2xl sm:rounded-2xl w-full max-w-lg p-6">
          <h3 className="font-semibold text-lg mb-4">Confirm Reminder</h3>
          <div className="bg-[#ECE5DD] rounded-lg p-4 mb-6">
            <WhatsAppMessage message={formatMessage(messageTemplates['friendly'].example, invoices.find(i => i.id === selectedInvoiceId)!)} />
          </div>
          <div className="flex gap-3">
            <button onClick={() => setShowSendConfirm(false)} className="flex-1 py-3 border rounded-lg">Cancel</button>
            <button onClick={async () => { await sendReminder(selectedInvoiceId, 'friendly'); setShowSendConfirm(false); }} className="flex-1 py-3 bg-[#25D366] text-white rounded-lg">Send Now</button>
          </div>
        </div>
      </div>
    )}
    {showPaymentLog && (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-end sm:items-center justify-center p-4">
        <div className="bg-white rounded-t-2xl sm:rounded-2xl w-full max-w-lg p-6">
          <h3 className="font-semibold text-lg mb-4">Record Payment</h3>
          <input type="number" placeholder="Amount" className="w-full p-3 border rounded-lg mb-4" defaultValue={invoices.find(i => i.id === selectedInvoiceId)?.amount} />
          <div className="flex gap-3">
            <button onClick={() => setShowPaymentLog(false)} className="flex-1 py-3 border rounded-lg">Cancel</button>
            <button onClick={async () => { await markAsPaid(selectedInvoiceId, { date: new Date().toISOString(), amount: 0, method: 'Cash', notes: '' }); setShowPaymentLog(false); }} className="flex-1 py-3 bg-emerald-600 text-white rounded-lg">Paid</button>
          </div>
        </div>
      </div>
    )}
  </>;

  return (
    <div className="min-h-screen bg-gray-50 pb-24">
      <div className="bg-white border-b sticky top-0 z-10">
        <div className="max-w-2xl mx-auto px-4 py-4 flex items-center justify-between">
          <div><h1 className="text-xl font-bold">Debt Chaser</h1><p className="text-sm text-gray-600">{invoices.length} invoices</p></div>
          <button onClick={() => setShowSettings(true)} className="p-2 hover:bg-gray-100 rounded-lg"><SettingsIcon className="w-6 h-6 text-gray-600" /></button>
        </div>
      </div>
      <div className="max-w-2xl mx-auto px-4 py-6 space-y-4">
        {invoices.length > 0 && (
          <div className="bg-gradient-to-br from-emerald-500 to-emerald-600 rounded-lg p-6 text-white">
            <div className="flex items-start justify-between mb-4">
              <div><p className="text-emerald-100 text-sm mb-1">Total Recovered</p><p className="text-4xl font-bold">R{analytics.totalRecovered.toLocaleString()}</p></div>
              <BarChart3 className="w-8 h-8 text-emerald-100" />
            </div>
            <div className="grid grid-cols-3 gap-4 pt-4 border-t border-emerald-400">
              <div><p className="text-emerald-100 text-xs">This Month</p><p className="font-semibold">R{analytics.thisMonthRecovered.toLocaleString()}</p></div>
              <div><p className="text-emerald-100 text-xs">Avg. Days</p><p className="font-semibold">{analytics.averageDaysToPayment}d</p></div>
              <div><p className="text-emerald-100 text-xs">Success</p><p className="font-semibold">{analytics.successRate}%</p></div>
            </div>
          </div>
        )}
        <div className="grid grid-cols-2 gap-4">
          <div className="bg-white rounded-lg border p-4">
            <div className="flex items-center gap-2 text-gray-600 text-sm mb-1"><DollarSign className="w-4 h-4" /><span>Outstanding</span></div>
            <p className="text-2xl font-bold">R{analytics.totalOutstanding.toLocaleString()}</p>
          </div>
          <div className="bg-white rounded-lg border p-4">
            <div className="flex items-center gap-2 text-red-600 text-sm mb-1"><AlertCircle className="w-4 h-4" /><span>Overdue</span></div>
            <p className="text-2xl font-bold text-red-600">R{analytics.overdueAmount.toLocaleString()}</p>
          </div>
        </div>
        {invoices.length === 0 ? (
          <div className="bg-white rounded-lg border p-12 text-center">
            <FileText className="w-16 h-16 text-gray-300 mx-auto mb-4" />
            <h3 className="text-lg font-semibold mb-2">No invoices yet</h3>
            <button onClick={() => setShowUpload(true)} className="bg-blue-600 text-white px-6 py-3 rounded-lg">Add Invoice</button>
          </div>
        ) : (
          <div className="bg-white rounded-lg border divide-y">
            <div className="px-4 py-3 bg-gray-50 flex items-center justify-between"><h2 className="font-semibold text-sm">All Invoices</h2><button onClick={() => setShowUpload(true)} className="text-blue-600 text-sm">+ Add</button></div>
            {invoices.map(invoice => (
              <button key={invoice.id} onClick={() => setSelectedInvoiceId(invoice.id)} className="w-full px-4 py-4 hover:bg-gray-50 text-left">
                <div className="flex items-start justify-between mb-2">
                  <div><p className="font-semibold">{invoice.clientName}</p><p className="text-xs text-gray-500">Due: {new Date(invoice.dueDate).toLocaleDateString('en-ZA')}</p></div>
                  <p className="font-bold">R{invoice.amount.toLocaleString()}</p>
                </div>
                <div className="flex items-center justify-between">
                  <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium ${getStatusColor(invoice.status)}`}>{invoice.status}</span>
                  {invoice.remindersSent > 0 && <span className="text-xs text-gray-400">{invoice.remindersSent} reminders</span>}
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
      <button onClick={() => setShowUpload(true)} className="fixed bottom-6 right-6 bg-blue-600 text-white p-4 rounded-full shadow-lg"><Plus className="w-6 h-6" /></button>
      {showSettings && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-md p-6">
            <div className="flex justify-between mb-4"><h3 className="font-bold text-lg">Settings</h3><button onClick={() => setShowSettings(false)}><X /></button></div>
            <div className="space-y-4">
              <div><label className="text-sm">Business Name</label><input type="text" value={settings.businessName} onChange={e => setSettings({...settings, businessName: e.target.value})} className="w-full p-2 border rounded" /></div>
              <button onClick={async () => { if(confirm('Reset all?')) { localStorage.clear(); window.location.reload(); } }} className="w-full py-2 text-red-600 border border-red-600 rounded">Reset Data</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export type InvoiceStatus = 'overdue' | 'pending' | 'upcoming' | 'paid' | 'disputed';
export type MessageTone = 'friendly' | 'firm' | 'urgent' | 'final' | 'balanced';

export interface Message {
  date: string;
  type: MessageTone;
  sent: boolean;
}

export interface Invoice {
  id: number;
  clientName: string;
  amount: number;
  dueDate: string;
  clientPhone: string;
  invoiceNumber: string;
  status: InvoiceStatus;
  remindersSent: number;
  messages: Message[];
  createdAt: string;
  paidDate?: string;
  paidAmount?: number;
  paymentMethod?: string;
  paymentNotes?: string;
  /* Added lastReminder field to store the date of the most recent reminder message */
  lastReminder?: string;
}

export interface Settings {
  businessName: string;
  messageStyle: string;
  firstReminderDays: number;
  escalationDays: number;
  workingHoursOnly: boolean;
  pauseWeekends: boolean;
  whatsappConnected: boolean;
}

export interface TeamMember {
  id: number;
  name: string;
  email: string;
  role: string;
  avatar: string;
}

export interface Analytics {
  totalRecovered: number;
  totalOutstanding: number;
  overdueAmount: number;
  thisMonthRecovered: number;
  averageDaysToPayment: number;
  successRate: number;
}

import React, { useState, useEffect, useCallback } from 'react';
import { 
  DollarSign, Clock, CheckCircle, AlertCircle, Send, Plus, ArrowLeft, 
  Calendar, User, FileText, MessageSquare, Camera, X, Check, Settings as SettingsIcon, 
  CreditCard, PauseCircle, Edit3, Bell, Smartphone, Building, Share2, Mail, 
  Download, ChevronRight, Zap, Shield, TrendingUp, Users, Link2, QrCode, 
  PhoneCall, BarChart3, TrendingDown, Copy, CheckCheck, Wifi, WifiOff, Trash2 
} from 'lucide-react';
import { 
  Invoice, Message, Settings, TeamMember, Analytics, 
  InvoiceStatus, MessageTone 
} from './types';

// Helper for storage types
interface StorageResult {
  value: string;
}

const messageTemplates: Record<string, { title: string; example: string }> = {
  friendly: {
    title: "Friendly Reminder",
    example: "Hi {name}! 👋 Just a gentle reminder that invoice #{number} for R{amount} was due on {date}. When can we expect payment? Let me know if you need the invoice resent. Thanks!"
  },
  firm: {
    title: "Firm Follow-up",
    example: "Hi {name}, invoice #{number} for R{amount} is now {days} days overdue. Please arrange payment this week. If there's an issue, let's discuss. Payment details attached."
  },
  urgent: {
    title: "Urgent Notice",
    example: "{name}, invoice #{number} (R{amount}) remains unpaid after {days} days. This is affecting our cashflow. Please prioritize payment immediately or contact me today to arrange a plan."
  },
  final: {
    title: "Final Notice",
    example: "{name}, FINAL NOTICE: Invoice #{number} for R{amount} is {days} days overdue. Payment must be received within 48 hours to avoid further action. Contact me urgently if there are any issues."
  }
};

export default function DebtChaser() {
  const [loading, setLoading] = useState(true);
  const [selectedInvoiceId, setSelectedInvoiceId] = useState<number | null>(null);
  const [showUpload, setShowUpload] = useState(false);
  const [showSendConfirm, setShowSendConfirm] = useState(false);
  const [showPaymentLog, setShowPaymentLog] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [showQRModal, setShowQRModal] = useState(false);
  const [shareStep, setShareStep] = useState<'options' | 'whatsapp' | 'link'>('options');
  const [copiedLink, setCopiedLink] = useState(false);
  const [hasSeenOnboarding, setHasSeenOnboarding] = useState(false);

  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [settings, setSettings] = useState<Settings>({
    businessName: "Your Business",
    messageStyle: "balanced",
    firstReminderDays: 2,
    escalationDays: 3,
    workingHoursOnly: true,
    pauseWeekends: false,
    whatsappConnected: true
  });
  const [teamMembers, setTeamMembers] = useState<TeamMember[]>([]);

  const loadData = useCallback(async () => {
    try {
      const storage = (window as any).storage;

      // Load invoices
      const invoicesResult: StorageResult | null = await storage.get('invoices');
      if (invoicesResult) {
        setInvoices(JSON.parse(invoicesResult.value));
      }

      // Load settings
      const settingsResult: StorageResult | null = await storage.get('settings');
      if (settingsResult) {
        setSettings(JSON.parse(settingsResult.value));
      }

      // Load team members
      const teamResult: StorageResult | null = await storage.get('team');
      if (teamResult) {
        setTeamMembers(JSON.parse(teamResult.value));
      } else {
        const defaultTeam = [
          { id: 1, name: "You", email: "you@business.com", role: "owner", avatar: "Y" }
        ];
        setTeamMembers(defaultTeam);
        await storage.set('team', JSON.stringify(defaultTeam));
      }

      // Check onboarding
      const onboardingResult = await storage.get('onboarding_complete');
      setHasSeenOnboarding(!!onboardingResult);

    } catch (error) {
      console.error('Initialization error:', error);
      setInvoices([]);
      setTeamMembers([{ id: 1, name: "You", email: "you@business.com", role: "owner", avatar: "Y" }]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const saveInvoices = async (newInvoices: Invoice[]) => {
    setInvoices(newInvoices);
    await (window as any).storage.set('invoices', JSON.stringify(newInvoices));
  };

  const saveSettings = async (newSettings: Settings) => {
    setSettings(newSettings);
    await (window as any).storage.set('settings', JSON.stringify(newSettings));
  };

  const getInvoiceStatus = (dueDate: string): InvoiceStatus => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const due = new Date(dueDate);
    due.setHours(0, 0, 0, 0);

    const diffTime = due.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return 'overdue';
    if (diffDays <= 3) return 'pending';
    return 'upcoming';
  };

  const getDaysOverdue = (dueDate: string) => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const due = new Date(dueDate);
    due.setHours(0, 0, 0, 0);

    const diffTime = today.getTime() - due.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    return diffDays > 0 ? diffDays : 0;
  };

  const addInvoice = async (invoiceData: Partial<Invoice>) => {
    const newInvoice: Invoice = {
      id: Date.now(),
      clientName: invoiceData.clientName || '',
      amount: invoiceData.amount || 0,
      dueDate: invoiceData.dueDate || '',
      clientPhone: invoiceData.clientPhone || '',
      invoiceNumber: invoiceData.invoiceNumber || '',
      status: getInvoiceStatus(invoiceData.dueDate || ''),
      remindersSent: 0,
      messages: [],
      createdAt: new Date().toISOString()
    };

    const updated = [...invoices, newInvoice];
    await saveInvoices(updated);
    return newInvoice;
  };

  const updateInvoice = async (id: number, updates: Partial<Invoice>) => {
    const updated = invoices.map(inv => 
      inv.id === id ? { ...inv, ...updates } : inv
    );
    await saveInvoices(updated);
  };

  const deleteInvoice = async (id: number) => {
    const updated = invoices.filter(inv => inv.id !== id);
    await saveInvoices(updated);
  };

  const markAsPaid = async (id: number, paymentData: { date: string; amount: number; method: string; notes: string }) => {
    await updateInvoice(id, {
      status: 'paid',
      paidDate: paymentData.date,
      paidAmount: paymentData.amount,
      paymentMethod: paymentData.method,
      paymentNotes: paymentData.notes
    });
  };

  const sendReminder = async (id: number, messageType: MessageTone) => {
    const invoice = invoices.find(inv => inv.id === id);
    if (!invoice) return;

    const newMessage: Message = {
      date: new Date().toISOString(),
      type: messageType,
      sent: true
    };

    /* Fix: lastReminder is now part of the Invoice interface in types.ts */
    await updateInvoice(id, {
      messages: [...invoice.messages, newMessage],
      remindersSent: invoice.remindersSent + 1,
      lastReminder: new Date().toISOString()
    });
  };

  const analytics: Analytics = {
    totalRecovered: invoices.filter(inv => inv.status === 'paid').reduce((sum, inv) => sum + (inv.paidAmount || inv.amount), 0),
    totalOutstanding: invoices.filter(inv => inv.status !== 'paid').reduce((sum, inv) => sum + inv.amount, 0),
    overdueAmount: invoices.filter(inv => inv.status === 'overdue').reduce((sum, inv) => sum + inv.amount, 0),
    thisMonthRecovered: invoices.filter(inv => {
      if (inv.status !== 'paid' || !inv.paidDate) return false;
      const paidDate = new Date(inv.paidDate);
      const now = new Date();
      return paidDate.getMonth() === now.getMonth() && paidDate.getFullYear() === now.getFullYear();
    }).reduce((sum, inv) => sum + (inv.paidAmount || inv.amount), 0),
    averageDaysToPayment: (() => {
      const paidInvoices = invoices.filter(inv => inv.status === 'paid' && inv.paidDate);
      if (paidInvoices.length === 0) return 0;
      const totalDays = paidInvoices.reduce((sum, inv) => {
        const due = new Date(inv.dueDate);
        const paid = new Date(inv.paidDate!);
        const days = Math.ceil((paid.getTime() - due.getTime()) / (1000 * 60 * 60 * 24));
        return sum + days;
      }, 0);
      return Math.round(totalDays / paidInvoices.length);
    })(),
    successRate: invoices.length > 0 ? Math.round((invoices.filter(inv => inv.status === 'paid').length / invoices.length) * 100) : 0
  };

  const getStatusColor = (status: InvoiceStatus) => {
    switch(status) {
      case 'overdue': return 'text-red-600 bg-red-50';
      case 'pending': return 'text-amber-600 bg-amber-50';
      case 'upcoming': return 'text-blue-600 bg-blue-50';
      case 'paid': return 'text-emerald-600 bg-emerald-50';
      case 'disputed': return 'text-purple-600 bg-purple-50';
      default: return 'text-gray-600 bg-gray-50';
    }
  };

  const getStatusIcon = (status: InvoiceStatus) => {
    switch(status) {
      case 'overdue': return AlertCircle;
      case 'pending': return Clock;
      case 'upcoming': return Calendar;
      case 'paid': return CheckCircle;
      case 'disputed': return PauseCircle;
      default: return FileText;
    }
  };

  const formatMessage = (template: string, invoice: Invoice) => {
    const daysOverdue = getDaysOverdue(invoice.dueDate);
    return template
      .replace('{name}', invoice.clientName.split("'")[0])
      .replace('{number}', invoice.invoiceNumber || `${invoice.id}`)
      .replace('{amount}', invoice.amount.toLocaleString())
      .replace('{date}', new Date(invoice.dueDate).toLocaleDateString('en-ZA'))
      .replace('{days}', daysOverdue.toString());
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopiedLink(true);
    setTimeout(() => setCopiedLink(false), 2000);
  };

  // Sub-components as per guidance (outside main body or defined clearly)

  const WhatsAppMessage: React.FC<{ message: string; sent?: boolean }> = ({ message, sent = true }) => (
    <div className={`flex ${sent ? 'justify-end' : 'justify-start'} mb-2`}>
      <div className={`max-w-[85%] rounded-lg px-4 py-2.5 ${
        sent ? 'bg-[#DCF8C6] text-gray-900' : 'bg-white text-gray-900 border'
      }`}>
        <p className="text-[15px] leading-relaxed whitespace-pre-wrap">{message}</p>
        <div className="flex items-center justify-end gap-1 mt-1">
          <span className="text-[11px] text-gray-500">
            {new Date().toLocaleTimeString('en-ZA', { hour: '2-digit', minute: '2-digit' })}
          </span>
          {sent && <Check className="w-4 h-4 text-blue-600" />}
        </div>
      </div>
    </div>
  );

  const OnboardingFlow = () => {
    const [step, setStep] = useState(0);
    const steps = [
      {
        title: "Welcome to Debt Chaser",
        subtitle: "Stop chasing. Start collecting.",
        description: "Automated WhatsApp reminders that get you paid faster - without the awkward phone calls.",
        icon: Zap,
        color: "blue"
      },
      {
        title: "How It Works",
        subtitle: "Three simple steps",
        steps: [
          { icon: Camera, text: "Upload your invoice (photo or WhatsApp)" },
          { icon: Send, text: "We send professional reminders automatically" },
          { icon: CheckCircle, text: "You get paid, we track everything" }
        ],
        icon: TrendingUp,
        color: "emerald"
      },
      {
        title: "You're In Control",
        subtitle: "Full transparency, no surprises",
        description: "Preview every message before it sends. Change the tone. Pause anytime. Your business, your rules.",
        icon: Shield,
        color: "purple"
      }
    ];

    const currentStep = steps[step];
    const isLastStep = step === steps.length - 1;

    return (
      <div className="fixed inset-0 bg-gradient-to-br from-blue-600 to-blue-800 z-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl w-full max-w-md overflow-hidden shadow-2xl">
          <div className="p-8 text-center">
            <div className={`inline-flex items-center justify-center w-20 h-20 rounded-full mb-6 ${
              currentStep.color === 'blue' ? 'bg-blue-100' :
              currentStep.color === 'emerald' ? 'bg-emerald-100' :
              'bg-purple-100'
            }`}>
              <currentStep.icon className={`w-10 h-10 ${
                currentStep.color === 'blue' ? 'text-blue-600' :
                currentStep.color === 'emerald' ? 'text-emerald-600' :
                'text-purple-600'
              }`} />
            </div>
            <h2 className="text-2xl font-bold text-gray-900 mb-2">{currentStep.title}</h2>
            <p className="text-lg text-gray-600 mb-6">{currentStep.subtitle}</p>
            {currentStep.description && (
              <p className="text-gray-700 leading-relaxed mb-6">{currentStep.description}</p>
            )}
            {currentStep.steps && (
              <div className="space-y-4 mb-6 text-left">
                {currentStep.steps.map((s, idx) => (
                  <div key={idx} className="flex items-start gap-4 p-4 bg-gray-50 rounded-lg">
                    <div className="flex-shrink-0 w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-sm">
                      <s.icon className="w-5 h-5 text-emerald-600" />
                    </div>
                    <p className="text-gray-700 pt-2">{s.text}</p>
                  </div>
                ))}
              </div>
            )}
            <div className="flex items-center justify-center gap-2 mb-6">
              {steps.map((_, idx) => (
                <div key={idx} className={`h-2 rounded-full transition-all ${idx === step ? 'w-8 bg-blue-600' : 'w-2 bg-gray-300'}`} />
              ))}
            </div>
            <div className="flex gap-3">
              {step > 0 && (
                <button onClick={() => setStep(step - 1)} className="flex-1 border border-gray-300 text-gray-700 py-3 rounded-lg font-medium hover:bg-gray-50 transition-colors">
                  Back
                </button>
              )}
              <button
                onClick={async () => {
                  if (isLastStep) {
                    await (window as any).storage.set('onboarding_complete', 'true');
                    setHasSeenOnboarding(true);
                    setShowUpload(true);
                  } else {
                    setStep(step + 1);
                  }
                }}
                className={`${step === 0 ? 'w-full' : 'flex-1'} bg-blue-600 text-white py-3 rounded-lg font-medium hover:bg-blue-700 transition-colors flex items-center justify-center gap-2`}
              >
                {isLastStep ? 'Add My First Invoice' : 'Continue'}
                <ChevronRight className="w-5 h-5" />
              </button>
            </div>
            <button
              onClick={async () => {
                await (window as any).storage.set('onboarding_complete', 'true');
                setHasSeenOnboarding(true);
              }}
              className="mt-4 text-sm text-gray-500 hover:text-gray-700"
            >
              Skip for now
            </button>
          </div>
        </div>
      </div>
    );
  };

  const UploadFlow = () => {
    const [formData, setFormData] = useState({
      clientName: '',
      amount: '',
      dueDate: '',
      clientPhone: '',
      invoiceNumber: ''
    });

    const handleSubmit = async () => {
      await addInvoice({
        clientName: formData.clientName,
        amount: parseFloat(formData.amount),
        dueDate: formData.dueDate,
        clientPhone: formData.clientPhone,
        invoiceNumber: formData.invoiceNumber
      });
      setShowUpload(false);
    };

    return (
      <div className="min-h-screen bg-gray-50 pb-20">
        <div className="bg-white border-b sticky top-0 z-10">
          <div className="max-w-2xl mx-auto px-4 py-4 flex items-center gap-3">
            <button onClick={() => setShowUpload(false)} className="p-2 hover:bg-gray-100 rounded-lg">
              <ArrowLeft className="w-5 h-5" />
            </button>
            <h1 className="text-lg font-semibold">Add New Invoice</h1>
          </div>
        </div>
        <div className="max-w-2xl mx-auto px-4 py-6 space-y-6">
          <div className="bg-white rounded-lg border p-6 space-y-5">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Client Name *</label>
              <input type="text" value={formData.clientName} onChange={(e) => setFormData({...formData, clientName: e.target.value})} placeholder="e.g. Thabo's Hardware" className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Invoice Amount (R) *</label>
              <input type="number" value={formData.amount} onChange={(e) => setFormData({...formData, amount: e.target.value})} placeholder="4500" className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Due Date *</label>
              <input type="date" value={formData.dueDate} onChange={(e) => setFormData({...formData, dueDate: e.target.value})} className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Client WhatsApp Number *</label>
              <input type="tel" value={formData.clientPhone} onChange={(e) => setFormData({...formData, clientPhone: e.target.value})} placeholder="+27 XX XXX XXXX" className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Invoice Number (Optional)</label>
              <input type="text" value={formData.invoiceNumber} onChange={(e) => setFormData({...formData, invoiceNumber: e.target.value})} placeholder="INV-001" className="w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500" />
            </div>
          </div>
          <button 
            onClick={handleSubmit} 
            disabled={!formData.clientName || !formData.amount || !formData.dueDate || !formData.clientPhone}
            className="w-full bg-blue-600 text-white py-4 rounded-lg font-semibold hover:bg-blue-700 transition-colors disabled:bg-gray-300"
          >
            Add Invoice
          </button>
        </div>
      </div>
    );
  };

  const InvoiceDetail = () => {
    const invoice = invoices.find(inv => inv.id === selectedInvoiceId);
    if (!invoice) return null;
    const StatusIcon = getStatusIcon(invoice.status);
    const daysOverdue = getDaysOverdue(invoice.dueDate);

    return (
      <div className="min-h-screen bg-gray-50 pb-20">
        <div className="bg-white border-b sticky top-0 z-10">
          <div className="max-w-2xl mx-auto px-4 py-4 flex items-center gap-3">
            <button onClick={() => setSelectedInvoiceId(null)} className="p-2 hover:bg-gray-100 rounded-lg">
              <ArrowLeft className="w-5 h-5" />
            </button>
            <div className="flex-1">
              <h1 className="text-lg font-semibold">{invoice.clientName}</h1>
              <p className="text-sm text-gray-500">Invoice {invoice.invoiceNumber || invoice.id}</p>
            </div>
            <button onClick={() => setShowQRModal(true)} className="p-2 hover:bg-gray-100 rounded-lg"><QrCode className="w-5 h-5" /></button>
            <button onClick={() => setShowShareModal(true)} className="p-2 hover:bg-gray-100 rounded-lg"><Share2 className="w-5 h-5" /></button>
            <button onClick={async () => { if(confirm('Delete?')) { await deleteInvoice(invoice.id); setSelectedInvoiceId(null); }}} className="p-2 hover:bg-gray-100 rounded-lg"><Trash2 className="w-5 h-5 text-red-600" /></button>
          </div>
        </div>
        <div className="max-w-2xl mx-auto px-4 py-6 space-y-6">
          <div className="bg-white rounded-lg border p-6">
            <div className="flex items-start justify-between mb-4">
              <div>
                <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-sm font-medium ${getStatusColor(invoice.status)}`}>
                  <StatusIcon className="w-4 h-4" />
                  {invoice.status === 'overdue' ? `${daysOverdue}d overdue` : invoice.status}
                </span>
                <p className="text-3xl font-bold text-gray-900 mt-2">R{invoice.amount.toLocaleString()}</p>
              </div>
            </div>
            <div className="space-y-2 text-sm border-t pt-4">
              <div className="flex justify-between"><span className="text-gray-600">Due date</span><span className="font-medium">{new Date(invoice.dueDate).toLocaleDateString('en-ZA')}</span></div>
              <div className="flex justify-between"><span className="text-gray-600">Client phone</span><span className="font-medium">{invoice.clientPhone}</span></div>
              {invoice.status === 'paid' && <div className="flex justify-between"><span className="text-gray-600">Paid date</span><span className="font-medium text-emerald-600">{new Date(invoice.paidDate!).toLocaleDateString('en-ZA')}</span></div>}
              <div className="flex justify-between"><span className="text-gray-600">Reminders sent</span><span className="font-medium">{invoice.remindersSent}</span></div>
            </div>
          </div>
          <div className="bg-white rounded-lg border">
            <div className="px-6 py-4 border-b"><h2 className="font-semibold">Message History</h2></div>
            <div className="p-6 space-y-4">
              {invoice.messages.length === 0 ? <p className="text-center text-gray-500 py-8">No messages sent yet</p> : 
                invoice.messages.map((msg, idx) => (
                  <div key={idx} className="border rounded-lg overflow-hidden">
                    <div className="flex items-center justify-between px-4 py-2 bg-gray-50 border-b">
                      <span className="text-xs font-semibold uppercase">{msg.type}</span>
                      <span className="text-xs text-gray-500">{new Date(msg.date).toLocaleDateString('en-ZA')}</span>
                    </div>
                    <div className="bg-[#ECE5DD] p-4"><WhatsAppMessage message={formatMessage(messageTemplates[msg.type].example, invoice)} /></div>
                  </div>
              ))}
            </div>
          </div>
          {invoice.status !== 'paid' && (
            <div className="space-y-3">
              <button onClick={() => setShowSendConfirm(true)} className="w-full bg-[#25D366] text-white py-3 rounded-lg font-medium flex items-center justify-center gap-2"><Send className="w-4 h-4" /> Send Reminder</button>
              <button onClick={() => setShowPaymentLog(true)} className="w-full border border-emerald-600 text-emerald-600 py-3 rounded-lg font-medium flex items-center justify-center gap-2"><CheckCircle className="w-4 h-4" /> Mark as Paid</button>
            </div>
          )}
        </div>
      </div>
    );
  };

  if (loading) return <div className="min-h-screen bg-gray-50 flex items-center justify-center animate-pulse">Loading...</div>;
  if (!hasSeenOnboarding) return <OnboardingFlow />;
  if (showUpload) return <UploadFlow />;
  if (selectedInvoiceId) return <><InvoiceDetail />
    {showSendConfirm && (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-end sm:items-center justify-center p-4">
        <div className="bg-white rounded-t-2xl sm:rounded-2xl w-full max-w-lg p-6">
          <h3 className="font-semibold text-lg mb-4">Confirm Reminder</h3>
          <div className="bg-[#ECE5DD] rounded-lg p-4 mb-6">
            <WhatsAppMessage message={formatMessage(messageTemplates['friendly'].example, invoices.find(i => i.id === selectedInvoiceId)!)} />
          </div>
          <div className="flex gap-3">
            <button onClick={() => setShowSendConfirm(false)} className="flex-1 py-3 border rounded-lg">Cancel</button>
            <button onClick={async () => { await sendReminder(selectedInvoiceId, 'friendly'); setShowSendConfirm(false); }} className="flex-1 py-3 bg-[#25D366] text-white rounded-lg">Send Now</button>
          </div>
        </div>
      </div>
    )}
    {showPaymentLog && (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-end sm:items-center justify-center p-4">
        <div className="bg-white rounded-t-2xl sm:rounded-2xl w-full max-w-lg p-6">
          <h3 className="font-semibold text-lg mb-4">Record Payment</h3>
          <input type="number" placeholder="Amount" className="w-full p-3 border rounded-lg mb-4" defaultValue={invoices.find(i => i.id === selectedInvoiceId)?.amount} />
          <div className="flex gap-3">
            <button onClick={() => setShowPaymentLog(false)} className="flex-1 py-3 border rounded-lg">Cancel</button>
            <button onClick={async () => { await markAsPaid(selectedInvoiceId, { date: new Date().toISOString(), amount: 0, method: 'Cash', notes: '' }); setShowPaymentLog(false); }} className="flex-1 py-3 bg-emerald-600 text-white rounded-lg">Paid</button>
          </div>
        </div>
      </div>
    )}
  </>;

  return (
    <div className="min-h-screen bg-gray-50 pb-24">
      <div className="bg-white border-b sticky top-0 z-10">
        <div className="max-w-2xl mx-auto px-4 py-4 flex items-center justify-between">
          <div><h1 className="text-xl font-bold">Debt Chaser</h1><p className="text-sm text-gray-600">{invoices.length} invoices</p></div>
          <button onClick={() => setShowSettings(true)} className="p-2 hover:bg-gray-100 rounded-lg"><SettingsIcon className="w-6 h-6 text-gray-600" /></button>
        </div>
      </div>
      <div className="max-w-2xl mx-auto px-4 py-6 space-y-4">
        {invoices.length > 0 && (
          <div className="bg-gradient-to-br from-emerald-500 to-emerald-600 rounded-lg p-6 text-white">
            <div className="flex items-start justify-between mb-4">
              <div><p className="text-emerald-100 text-sm mb-1">Total Recovered</p><p className="text-4xl font-bold">R{analytics.totalRecovered.toLocaleString()}</p></div>
              <BarChart3 className="w-8 h-8 text-emerald-100" />
            </div>
            <div className="grid grid-cols-3 gap-4 pt-4 border-t border-emerald-400">
              <div><p className="text-emerald-100 text-xs">This Month</p><p className="font-semibold">R{analytics.thisMonthRecovered.toLocaleString()}</p></div>
              <div><p className="text-emerald-100 text-xs">Avg. Days</p><p className="font-semibold">{analytics.averageDaysToPayment}d</p></div>
              <div><p className="text-emerald-100 text-xs">Success</p><p className="font-semibold">{analytics.successRate}%</p></div>
            </div>
          </div>
        )}
        <div className="grid grid-cols-2 gap-4">
          <div className="bg-white rounded-lg border p-4">
            <div className="flex items-center gap-2 text-gray-600 text-sm mb-1"><DollarSign className="w-4 h-4" /><span>Outstanding</span></div>
            <p className="text-2xl font-bold">R{analytics.totalOutstanding.toLocaleString()}</p>
          </div>
          <div className="bg-white rounded-lg border p-4">
            <div className="flex items-center gap-2 text-red-600 text-sm mb-1"><AlertCircle className="w-4 h-4" /><span>Overdue</span></div>
            <p className="text-2xl font-bold text-red-600">R{analytics.overdueAmount.toLocaleString()}</p>
          </div>
        </div>
        {invoices.length === 0 ? (
          <div className="bg-white rounded-lg border p-12 text-center">
            <FileText className="w-16 h-16 text-gray-300 mx-auto mb-4" />
            <h3 className="text-lg font-semibold mb-2">No invoices yet</h3>
            <button onClick={() => setShowUpload(true)} className="bg-blue-600 text-white px-6 py-3 rounded-lg">Add Invoice</button>
          </div>
        ) : (
          <div className="bg-white rounded-lg border divide-y">
            <div className="px-4 py-3 bg-gray-50 flex items-center justify-between"><h2 className="font-semibold text-sm">All Invoices</h2><button onClick={() => setShowUpload(true)} className="text-blue-600 text-sm">+ Add</button></div>
            {invoices.map(invoice => (
              <button key={invoice.id} onClick={() => setSelectedInvoiceId(invoice.id)} className="w-full px-4 py-4 hover:bg-gray-50 text-left">
                <div className="flex items-start justify-between mb-2">
                  <div><p className="font-semibold">{invoice.clientName}</p><p className="text-xs text-gray-500">Due: {new Date(invoice.dueDate).toLocaleDateString('en-ZA')}</p></div>
                  <p className="font-bold">R{invoice.amount.toLocaleString()}</p>
                </div>
                <div className="flex items-center justify-between">
                  <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium ${getStatusColor(invoice.status)}`}>{invoice.status}</span>
                  {invoice.remindersSent > 0 && <span className="text-xs text-gray-400">{invoice.remindersSent} reminders</span>}
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
      <button onClick={() => setShowUpload(true)} className="fixed bottom-6 right-6 bg-blue-600 text-white p-4 rounded-full shadow-lg"><Plus className="w-6 h-6" /></button>
      {showSettings && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-md p-6">
            <div className="flex justify-between mb-4"><h3 className="font-bold text-lg">Settings</h3><button onClick={() => setShowSettings(false)}><X /></button></div>
            <div className="space-y-4">
              <div><label className="text-sm">Business Name</label><input type="text" value={settings.businessName} onChange={e => setSettings({...settings, businessName: e.target.value})} className="w-full p-2 border rounded" /></div>
              <button onClick={async () => { if(confirm('Reset all?')) { localStorage.clear(); window.location.reload(); } }} className="w-full py-2 text-red-600 border border-red-600 rounded">Reset Data</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import { 
  DollarSign, Clock, CheckCircle, AlertCircle, Send, Plus, ArrowLeft, 
  Calendar, User, FileText, MessageSquare, Camera, X, Check, Settings as SettingsIcon, 
  CreditCard, PauseCircle, Edit3, Bell, Smartphone, Building, Share2, Mail, 
  Download, ChevronRight, Zap, Shield, TrendingUp, Users, Link2, QrCode, 
  PhoneCall, BarChart3, TrendingDown, Copy, CheckCheck, Wifi, WifiOff, Trash2 
} from 'lucide-react';
import { 
  Invoice, Message, Settings, TeamMember, Analytics, 
  InvoiceStatus, MessageTone 
} from './types';

// Helper for storage types
interface StorageResult {
  value: string;
}

const messageTemplates: Record<string, { title: string; example: string }> = {
  friendly: {
    title: "Friendly Reminder",
    example: "Hi {name}! 👋 Just a gentle reminder that invoice #{number} for R{amount} was due on {date}. When can we expect payment? Let me know if you need the invoice resent. Thanks!"
  },
  firm: {
    title: "Firm Follow-up",
    example: "Hi {name}, invoice #{number} for R{amount} is now {days} days overdue. Please arrange payment this week. If there's an issue, let's discuss. Payment details attached."
  },
  urgent: {
    title: "Urgent Notice",
    example: "{name}, invoice #{number} (R{amount}) remains unpaid after {days} days. This is affecting our cashflow. Please prioritize payment immediately or contact me today to arrange a plan."
  },
  final: {
    title: "Final Notice",
    example: "{name}, FINAL NOTICE: Invoice #{number} for R{amount} is {days} days overdue. Payment must be received within 48 hours to avoid further action. Contact me urgently if there are any issues."
  }
};

export default function DebtChaser() {
  const [loading, setLoading] = useState(true);
  const [selectedInvoiceId, setSelectedInvoiceId] = useState<number | null>(null);
  const [showUpload, setShowUpload] = useState(false);
  const [showSendConfirm, setShowSendConfirm] = useState(false);
  const [showPaymentLog, setShowPaymentLog] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [showQRModal, setShowQRModal] = useState(false);
  const [shareStep, setShareStep] = useState<'options' | 'whatsapp' | 'link'>('options');
  const [copiedLink, setCopiedLink] = useState(false);
  const [hasSeenOnboarding, setHasSeenOnboarding] = useState(false);

  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [settings, setSettings] = useState<Settings>({
    businessName: "Your Business",
    messageStyle: "balanced",
    firstReminderDays: 2,
    escalationDays: 3,
    workingHoursOnly: true,
    pauseWeekends: false,
    whatsappConnected: true
  });
  const [teamMembers, setTeamMembers] = useState<TeamMember[]>([]);

  const loadData = useCallback(async () => {
    try {
      const storage = (window as any).storage;

      // Load invoices
      const invoicesResult: StorageResult | null = await storage.get('invoices');
      if (invoicesResult) {
        setInvoices(JSON.parse(invoicesResult.value));
      }

      // Load settings
      const settingsResult: StorageResult | null = await storage.get('settings');
      if (settingsResult) {
        setSettings(JSON.parse(settingsResult.value));
      }

      // Load team members
      const teamResult: StorageResult | null = await storage.get('team');
      if (teamResult) {
        setTeamMembers(JSON.parse(teamResult.value));
      } else {
        const defaultTeam = [
          { id: 1, name: "You", email: "you@business.com", role: "owner", avatar: "Y" }
        ];
        setTeamMembers(defaultTeam);
        await storage.set('team', JSON.stringify(defaultTeam));
      }

      // Check onboarding
      const onboardingResult = await storage.get('onboarding_complete');
      setHasSeenOnboarding(!!onboardingResult);

    } catch (error) {
      console.error('Initialization error:', error);
      setInvoices([]);
      setTeamMembers([{ id: 1, name: "You", email: "you@business.com", role: "owner", avatar: "Y" }]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const saveInvoices = async (newInvoices: Invoice[]) => {
    setInvoices(newInvoices);
    await (window as any).storage.set('invoices', JSON.stringify(newInvoices));
  };

  const saveSettings = async (newSettings: Settings) => {
    setSettings(newSettings);
    await (window as any).storage.set('settings', JSON.stringify(newSettings));
  };

  const getInvoiceStatus = (dueDate: string): InvoiceStatus => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const due = new Date(dueDate);
    due.setHours(0, 0, 0, 0);

    const diffTime = due.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return 'overdue';
    if (diffDays <= 3) return 'pending';
    return 'upcoming';
  };

  const getDaysOverdue = (dueDate: string) => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const due = new Date(dueDate);
    due.setHours(0, 0, 0, 0);

    const diffTime = today.getTime() - due.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    return diffDays > 0 ? diffDays : 0;
  };

  const addInvoice = async (invoiceData: Partial<Invoice>) => {
    const newInvoice: Invoice = {
      id: Date.now(),
      clientName: invoiceData.clientName || '',
      amount: invoiceData.amount || 0,
      dueDate: invoiceData.dueDate || '',
      clientPhone: invoiceData.clientPhone || '',
      invoiceNumber: invoiceData.invoiceNumber || '',
      status: getInvoiceStatus(invoiceData.dueDate || ''),
      remindersSent: 0,
      messages: [],
      createdAt: new Date().toISOString()
    };

    const updated = [...invoices, newInvoice];
    await saveInvoices(updated);
    return newInvoice;
  };

  const updateInvoice = async (id: number, updates: Partial<Invoice>) => {
    const updated = invoices.map(inv => 
      inv.id === id ? { ...inv, ...updates } : inv
    );
    await saveInvoices(updated);
  };

  const deleteInvoice = async (id: number) => {
    const updated = invoices.filter(inv => inv.id !== id);
    await saveInvoices(updated);
  };

  const markAsPaid = async (id: number, paymentData: { date: string; amount: number; method: string; notes: string }) => {
    await updateInvoice(id, {
      status: 'paid',
      paidDate: paymentData.date,
      paidAmount: paymentData.amount,
      paymentMethod: paymentData.method,
      paymentNotes: paymentData.notes
    });
  };

  const sendReminder = async (id: number, messageType: MessageTone) => {
    const invoice = invoices.find(inv => inv.id === id);
    if (!invoice) return;

    const newMessage: Message = {
      date: new Date().toISOString(),
      type: messageType,
      sent: true
    };

    /* Fix: lastReminder is now part of the Invoice interface in types.ts */
    await updateInvoice(id, {
      messages: [...invoice.messages, newMessage],
      remindersSent: invoice.remindersSent + 1,
      lastReminder: new Date().toISOString()
    });
  };

  const analytics: Analytics = {
    totalRecovered: invoices.filter(inv => inv.status === 'paid').reduce((sum, inv) => sum + (inv.paidAmount || inv.amount), 0),
    totalOutstanding: invoices.filter(inv => inv.status !== 'paid').reduce((sum, inv) => sum + inv.amount, 0),
    overdueAmount: invoices.filter(inv => inv.status === 'overdue').reduce((sum, inv) => sum + inv.amount, 0),
    thisMonthRecovered: invoices.filter(inv => {
      if (inv.status !== 'paid' || !inv.paidDate) return false;
      const paidDate = new Date(inv.paidDate);
      const now = new Date();
      return paidDate.getMonth() === now.getMonth() && paidDate.getFullYear() === now.getFullYear();
    }).reduce((sum, inv) => sum + (inv.paidAmount || inv.amount), 0),
    averageDaysToPayment: (() => {
      const paidInvoices = invoices.filter(inv => inv.status === 'paid' && inv.paidDate);
      if (paidInvoices.length === 0) return 0;
      const totalDays = paidInvoices.reduce((sum, inv) => {
        const due = new Date(inv.dueDate);
        const paid = new Date(inv.paidDate!);
        const days = Math.ceil((paid.getTime() - due.getTime()) / (1000 * 60 * 60 * 24));
        return sum + days;
      }, 0);
      return Math.round(totalDays / paidInvoices.length);
    })(),
    successRate: invoices.length > 0 ? Math.round((invoices.filter(inv => inv.status === 'paid').length / invoices.length) * 100) : 0
  };

  const getStatusColor = (status: InvoiceStatus) => {
    switch(status) {
      case 'overdue': return 'text-red-600 bg-red-50';
      case 'pending': return 'text-amber-600 bg-amber-50';
      case 'upcoming': return 'text-blue-600 bg-blue-50';
      case 'paid': return 'text-emerald-600 bg-emerald-50';
      case 'disputed': return 'text-purple-600 bg-purple-50';
      default: return 'text-gray-600 bg-gray-50';
    }
  };

  const getStatusIcon = (status: InvoiceStatus) => {
    switch(status) {
      case 'overdue': return AlertCircle;
      case 'pending': return Clock;
      case 'upcoming': return Calendar;
      case 'paid': return CheckCircle;
      case 'disputed': return PauseCircle;
      default: return FileText;
    }
  };

  const formatMessage = (template: string, invoice: Invoice) => {
    const daysOverdue = getDaysOverdue(invoice.dueDate);
    return template
      .replace('{name}', invoice.clientName.split("'")[0])
      .replace('{number}', invoice.invoiceNumber || `${invoice.id}`)
      .replace('{amount}', invoice.amount.toLocaleString())
      .replace('{date}', new Date(invoice.dueDate).toLocaleDateString('en-ZA'))
      .replace('{days}', daysOverdue.toString());
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopiedLink(true);
    setTimeout(() => setCopiedLink(false), 2000);
  };

  // Sub-components as per guidance (outside main body or defined clearly)

  const WhatsAppMessage: React.FC<{ message: string; sent?: boolean }> = ({ message, sent = true }) => (
    <div className={`flex ${sent ? 'justify-end' : 'justify-start'} mb-2`}>
      <div className={`max-w-[85%] rounded-lg px-4 py-2.5 ${
        sent ? 'bg-[#DCF8C6] text-gray-900' : 'bg-white text-gray-900 border'
      }`}>
        <p className="text-[15px] leading-relaxed whitespace-pre-wrap">{message}</p>
        <div className="flex items-center justify-end gap-1 mt-1">
          <span className="text-[11px] text-gray-500">
            {new Date().toLocaleTimeString('en-ZA', { hour: '2-digit', minute: '2-digit' })}
          </span>
          {sent && <Check className="w-4 h-4 text-blue-600" />}
        </div>
      </div>
    </div>
  );

  const OnboardingFlow = () => {
    const [step, setStep] = useState(0);
    const steps = [
      {
        title: "Welcome to Debt Chaser",
        subtitle: "Stop chasing. Start collecting.",
        description: "Automated WhatsApp reminders that get you paid faster - without the awkward phone calls.",
        icon: Zap,
        color: "blue"
      },
      {
        title: "How It Works",
        subtitle: "Three simple steps",
        steps: [
          { icon: Camera, text: "Upload your invoice (photo or WhatsApp)" },
          { icon: Send, text: "We send professional reminders automatically" },
          { icon: CheckCircle, text: "You get paid, we track everything" }
        ],
        icon: TrendingUp,
        color: "emerald"
      },
      {
        title: "You're In Control",
        subtitle: "Full transparency, no surprises",
        description: "Preview every message before it sends. Change the tone. Pause anytime. Your business, your rules.",
        icon: Shield,
        color: "purple"
      }
    ];

    const currentStep = steps[step];
    const isLastStep = step === steps.length - 1;

    return (
      <div className="fixed inset-0 bg-gradient-to-br from-blue-600 to-blue-800 z-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl w-full max-w-md overflow-hidden shadow-2xl">
          <div className="p-8 text-center">
            <div className={`inline-flex items-center justify-center w-20 h-20 rounded-full mb-6 ${
              currentStep.color === 'blue' ? 'bg-blue-100' :
              currentStep.color === 'emerald' ? 'bg-emerald-100' :
              'bg-purple-100'
            }`}>
              <currentStep.icon className={`w-10 h-10 ${
                currentStep.color === 'blue' ? 'text-blue-600' :
                currentStep.color === 'emerald' ? 'text-emerald-600' :
                'text-purple-600'
              }`} />
            </div>
            <h2 className="text-2xl font-bold text-gray-900 mb-2">{currentStep.title}</h2>
            <p className="text-lg text-gray-600 mb-6">{currentStep.subtitle}</p>
            {currentStep.description && (
              <p className="text-gray-700 leading-relaxed mb-6">{currentStep.description}</p>
            )}
            {currentStep.steps && (
              <div className="space-y-4 mb-6 text-left">
                {currentStep.steps.map((s, idx) => (
                  <div key={idx} className="flex items-start gap-4 p-4 bg-gray-50 rounded-lg">
                    <div className="flex-shrink-0 w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-sm">
                      <s.icon className="w-5 h-5 text-emerald-600" />
                    </div>
                    <p className="text-gray-700 pt-2">{s.text}</p>
                  </div>
                ))}
              </div>
            )}
            <div className="flex items-center justify-center gap-2 mb-6">
              {steps.map((_, idx) => (
                <div key={idx} className={`h-2 rounded-full transition-all ${idx === step ? 'w-8 bg-blue-600' : 'w-2 bg-gray-300'}`} />
              ))}
            </div>
            <div className="flex gap-3">
              {step > 0 && (
                <button onClick={() => setStep(step - 1)} className="flex-1 border border-gray-300 text-gray-700 py-3 rounded-lg font-medium hover:bg-gray-50 transition-colors">
                  Back
                </button>
              )}
              <button
                onClick={async () => {
                  if (isLastStep) {
                    await (window as any).storage.set('onboarding_complete', 'true');
                    setHasSeenOnboarding(true);
                    setShowUpload(true);
                  } else {
                    setStep(step + 1);
                  }
                }}
                className={`${step === 0 ? 'w-full' : 'flex-1'} bg-blue-600 text-white py-3 rounded-lg font-medium hover:bg-blue-700 transition-colors flex items-center justify-center gap-2`}
              >
                {isLastStep ? 'Add My First Invoice' : 'Continue'}
                <ChevronRight className="w-5 h-5" />
              </button>
            </div>
            <button
              onClick={async () => {
                await (window as any).storage.set('onboarding_complete', 'true');
                setHasSeenOnboarding(true);
              }}
              className="mt-4 text-sm text-gray-500 hover:text-gray-700"
            >
              Skip for now
            </button>
          </div>
        </div>
      </div>
    );
  };

  const UploadFlow = () => {
    const [formData, setFormData] = useState({
      clientName: '',
      amount: '',
      dueDate: '',
      clientPhone: '',
      invoiceNumber: ''
    });

    const handleSubmit = async () => {
      await addInvoice({
        clientName: formData.clientName,
        amount: parseFloat(formData.amount),
        dueDate: formData.dueDate,
        clientPhone: formData.clientPhone,
        invoiceNumber: formData.invoiceNumber
      });
      setShowUpload(false);
    };

    // Shared input class for consistency and clarity
    const inputClass = "w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-white text-gray-900 placeholder-gray-400";

    return (
      <div className="min-h-screen bg-gray-50 pb-20">
        <div className="bg-white border-b sticky top-0 z-10">
          <div className="max-w-2xl mx-auto px-4 py-4 flex items-center gap-3">
            <button onClick={() => setShowUpload(false)} className="p-2 hover:bg-gray-100 rounded-lg">
              <ArrowLeft className="w-5 h-5" />
            </button>
            <h1 className="text-lg font-semibold">Add New Invoice</h1>
          </div>
        </div>
        <div className="max-w-2xl mx-auto px-4 py-6 space-y-6">
          <div className="bg-white rounded-lg border p-6 space-y-5">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Client Name *</label>
              <input type="text" value={formData.clientName} onChange={(e) => setFormData({...formData, clientName: e.target.value})} placeholder="e.g. Thabo's Hardware" className={inputClass} />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Invoice Amount (R) *</label>
              <input type="number" value={formData.amount} onChange={(e) => setFormData({...formData, amount: e.target.value})} placeholder="4500" className={inputClass} />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Due Date *</label>
              <input type="date" value={formData.dueDate} onChange={(e) => setFormData({...formData, dueDate: e.target.value})} className={inputClass} />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Client WhatsApp Number *</label>
              <input type="tel" value={formData.clientPhone} onChange={(e) => setFormData({...formData, clientPhone: e.target.value})} placeholder="+27 XX XXX XXXX" className={inputClass} />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Invoice Number (Optional)</label>
              <input type="text" value={formData.invoiceNumber} onChange={(e) => setFormData({...formData, invoiceNumber: e.target.value})} placeholder="INV-001" className={inputClass} />
            </div>
          </div>
          <button 
            onClick={handleSubmit} 
            disabled={!formData.clientName || !formData.amount || !formData.dueDate || !formData.clientPhone}
            className="w-full bg-blue-600 text-white py-4 rounded-lg font-semibold hover:bg-blue-700 transition-colors disabled:bg-gray-300 shadow-md"
          >
            Add Invoice
          </button>
        </div>
      </div>
    );
  };

  const InvoiceDetail = () => {
    const invoice = invoices.find(inv => inv.id === selectedInvoiceId);
    if (!invoice) return null;
    const StatusIcon = getStatusIcon(invoice.status);
    const daysOverdue = getDaysOverdue(invoice.dueDate);

    return (
      <div className="min-h-screen bg-gray-50 pb-20">
        <div className="bg-white border-b sticky top-0 z-10">
          <div className="max-w-2xl mx-auto px-4 py-4 flex items-center gap-3">
            <button onClick={() => setSelectedInvoiceId(null)} className="p-2 hover:bg-gray-100 rounded-lg">
              <ArrowLeft className="w-5 h-5" />
            </button>
            <div className="flex-1">
              <h1 className="text-lg font-semibold">{invoice.clientName}</h1>
              <p className="text-sm text-gray-500">Invoice {invoice.invoiceNumber || invoice.id}</p>
            </div>
            <button onClick={() => setShowQRModal(true)} className="p-2 hover:bg-gray-100 rounded-lg"><QrCode className="w-5 h-5" /></button>
            <button onClick={() => setShowShareModal(true)} className="p-2 hover:bg-gray-100 rounded-lg"><Share2 className="w-5 h-5" /></button>
            <button onClick={async () => { if(confirm('Delete?')) { await deleteInvoice(invoice.id); setSelectedInvoiceId(null); }}} className="p-2 hover:bg-gray-100 rounded-lg"><Trash2 className="w-5 h-5 text-red-600" /></button>
          </div>
        </div>
        <div className="max-w-2xl mx-auto px-4 py-6 space-y-6">
          <div className="bg-white rounded-lg border p-6">
            <div className="flex items-start justify-between mb-4">
              <div>
                <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-sm font-medium ${getStatusColor(invoice.status)}`}>
                  <StatusIcon className="w-4 h-4" />
                  {invoice.status === 'overdue' ? `${daysOverdue}d overdue` : invoice.status}
                </span>
                <p className="text-3xl font-bold text-gray-900 mt-2">R{invoice.amount.toLocaleString()}</p>
              </div>
            </div>
            <div className="space-y-2 text-sm border-t pt-4">
              <div className="flex justify-between"><span className="text-gray-600">Due date</span><span className="font-medium">{new Date(invoice.dueDate).toLocaleDateString('en-ZA')}</span></div>
              <div className="flex justify-between"><span className="text-gray-600">Client phone</span><span className="font-medium">{invoice.clientPhone}</span></div>
              {invoice.status === 'paid' && <div className="flex justify-between"><span className="text-gray-600">Paid date</span><span className="font-medium text-emerald-600">{new Date(invoice.paidDate!).toLocaleDateString('en-ZA')}</span></div>}
              <div className="flex justify-between"><span className="text-gray-600">Reminders sent</span><span className="font-medium">{invoice.remindersSent}</span></div>
            </div>
          </div>
          <div className="bg-white rounded-lg border">
            <div className="px-6 py-4 border-b"><h2 className="font-semibold">Message History</h2></div>
            <div className="p-6 space-y-4">
              {invoice.messages.length === 0 ? <p className="text-center text-gray-500 py-8">No messages sent yet</p> : 
                invoice.messages.map((msg, idx) => (
                  <div key={idx} className="border rounded-lg overflow-hidden">
                    <div className="flex items-center justify-between px-4 py-2 bg-gray-50 border-b">
                      <span className="text-xs font-semibold uppercase">{msg.type}</span>
                      <span className="text-xs text-gray-500">{new Date(msg.date).toLocaleDateString('en-ZA')}</span>
                    </div>
                    <div className="bg-[#ECE5DD] p-4"><WhatsAppMessage message={formatMessage(messageTemplates[msg.type].example, invoice)} /></div>
                  </div>
              ))}
            </div>
          </div>
          {invoice.status !== 'paid' && (
            <div className="space-y-3">
              <button onClick={() => setShowSendConfirm(true)} className="w-full bg-[#25D366] text-white py-3 rounded-lg font-medium flex items-center justify-center gap-2"><Send className="w-4 h-4" /> Send Reminder</button>
              <button onClick={() => setShowPaymentLog(true)} className="w-full border border-emerald-600 text-emerald-600 py-3 rounded-lg font-medium flex items-center justify-center gap-2"><CheckCircle className="w-4 h-4" /> Mark as Paid</button>
            </div>
          )}
        </div>
      </div>
    );
  };

  if (loading) return <div className="min-h-screen bg-gray-50 flex items-center justify-center animate-pulse">Loading...</div>;
  if (!hasSeenOnboarding) return <OnboardingFlow />;
  if (showUpload) return <UploadFlow />;
  if (selectedInvoiceId) return <><InvoiceDetail />
    {showSendConfirm && (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-end sm:items-center justify-center p-4">
        <div className="bg-white rounded-t-2xl sm:rounded-2xl w-full max-w-lg p-6">
          <h3 className="font-semibold text-lg mb-4">Confirm Reminder</h3>
          <div className="bg-[#ECE5DD] rounded-lg p-4 mb-6">
            <WhatsAppMessage message={formatMessage(messageTemplates['friendly'].example, invoices.find(i => i.id === selectedInvoiceId)!)} />
          </div>
          <div className="flex gap-3">
            <button onClick={() => setShowSendConfirm(false)} className="flex-1 py-3 border rounded-lg">Cancel</button>
            <button onClick={async () => { await sendReminder(selectedInvoiceId, 'friendly'); setShowSendConfirm(false); }} className="flex-1 py-3 bg-[#25D366] text-white rounded-lg">Send Now</button>
          </div>
        </div>
      </div>
    )}
    {showPaymentLog && (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-end sm:items-center justify-center p-4">
        <div className="bg-white rounded-t-2xl sm:rounded-2xl w-full max-w-lg p-6">
          <h3 className="font-semibold text-lg mb-4">Record Payment</h3>
          <div className="mb-6">
             <label className="block text-sm font-medium text-gray-700 mb-2">Amount Received (R)</label>
             <input type="number" placeholder="Amount" className="w-full p-3 border border-gray-300 rounded-lg text-gray-900 bg-white" defaultValue={invoices.find(i => i.id === selectedInvoiceId)?.amount} />
          </div>
          <div className="flex gap-3">
            <button onClick={() => setShowPaymentLog(false)} className="flex-1 py-3 border rounded-lg text-gray-700">Cancel</button>
            <button onClick={async () => { await markAsPaid(selectedInvoiceId, { date: new Date().toISOString(), amount: 0, method: 'Cash', notes: '' }); setShowPaymentLog(false); }} className="flex-1 py-3 bg-emerald-600 text-white rounded-lg font-medium">Confirm Payment</button>
          </div>
        </div>
      </div>
    )}
  </>;

  return (
    <div className="min-h-screen bg-gray-50 pb-24">
      <div className="bg-white border-b sticky top-0 z-10">
        <div className="max-w-2xl mx-auto px-4 py-4 flex items-center justify-between">
          <div><h1 className="text-xl font-bold">Debt Chaser</h1><p className="text-sm text-gray-600">{invoices.length} invoices</p></div>
          <button onClick={() => setShowSettings(true)} className="p-2 hover:bg-gray-100 rounded-lg"><SettingsIcon className="w-6 h-6 text-gray-600" /></button>
        </div>
      </div>
      <div className="max-w-2xl mx-auto px-4 py-6 space-y-4">
        {invoices.length > 0 && (
          <div className="bg-gradient-to-br from-emerald-500 to-emerald-600 rounded-lg p-6 text-white shadow-sm">
            <div className="flex items-start justify-between mb-4">
              <div><p className="text-emerald-100 text-sm mb-1">Total Recovered</p><p className="text-4xl font-bold">R{analytics.totalRecovered.toLocaleString()}</p></div>
              <BarChart3 className="w-8 h-8 text-emerald-100" />
            </div>
            <div className="grid grid-cols-3 gap-4 pt-4 border-t border-emerald-400">
              <div><p className="text-emerald-100 text-xs">This Month</p><p className="font-semibold">R{analytics.thisMonthRecovered.toLocaleString()}</p></div>
              <div><p className="text-emerald-100 text-xs">Avg. Days</p><p className="font-semibold">{analytics.averageDaysToPayment}d</p></div>
              <div><p className="text-emerald-100 text-xs">Success</p><p className="font-semibold">{analytics.successRate}%</p></div>
            </div>
          </div>
        )}
        <div className="grid grid-cols-2 gap-4">
          <div className="bg-white rounded-lg border p-4 shadow-sm">
            <div className="flex items-center gap-2 text-gray-600 text-sm mb-1"><DollarSign className="w-4 h-4" /><span>Outstanding</span></div>
            <p className="text-2xl font-bold text-gray-900">R{analytics.totalOutstanding.toLocaleString()}</p>
          </div>
          <div className="bg-white rounded-lg border p-4 shadow-sm">
            <div className="flex items-center gap-2 text-red-600 text-sm mb-1"><AlertCircle className="w-4 h-4" /><span>Overdue</span></div>
            <p className="text-2xl font-bold text-red-600">R{analytics.overdueAmount.toLocaleString()}</p>
          </div>
        </div>
        {invoices.length === 0 ? (
          <div className="bg-white rounded-lg border p-12 text-center shadow-sm">
            <FileText className="w-16 h-16 text-gray-300 mx-auto mb-4" />
            <h3 className="text-lg font-semibold mb-2">No invoices yet</h3>
            <button onClick={() => setShowUpload(true)} className="bg-blue-600 text-white px-6 py-3 rounded-lg shadow-sm hover:bg-blue-700">Add Invoice</button>
          </div>
        ) : (
          <div className="bg-white rounded-lg border divide-y shadow-sm">
            <div className="px-4 py-3 bg-gray-50 flex items-center justify-between"><h2 className="font-semibold text-sm text-gray-700">All Invoices</h2><button onClick={() => setShowUpload(true)} className="text-blue-600 text-sm font-medium">+ Add</button></div>
            {invoices.map(invoice => (
              <button key={invoice.id} onClick={() => setSelectedInvoiceId(invoice.id)} className="w-full px-4 py-4 hover:bg-gray-50 text-left transition-colors">
                <div className="flex items-start justify-between mb-2">
                  <div><p className="font-semibold text-gray-900">{invoice.clientName}</p><p className="text-xs text-gray-500">Due: {new Date(invoice.dueDate).toLocaleDateString('en-ZA')}</p></div>
                  <p className="font-bold text-gray-900">R{invoice.amount.toLocaleString()}</p>
                </div>
                <div className="flex items-center justify-between">
                  <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium ${getStatusColor(invoice.status)}`}>{invoice.status}</span>
                  {invoice.remindersSent > 0 && <span className="text-xs text-gray-400">{invoice.remindersSent} reminders</span>}
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
      <button onClick={() => setShowUpload(true)} className="fixed bottom-6 right-6 bg-blue-600 text-white p-4 rounded-full shadow-lg hover:bg-blue-700 transition-transform active:scale-95"><Plus className="w-6 h-6" /></button>
      {showSettings && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-md p-6 shadow-xl">
            <div className="flex justify-between mb-6"><h3 className="font-bold text-lg text-gray-900">Settings</h3><button onClick={() => setShowSettings(false)} className="text-gray-400 hover:text-gray-600"><X /></button></div>
            <div className="space-y-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Business Name</label>
                <input type="text" value={settings.businessName} onChange={e => setSettings({...settings, businessName: e.target.value})} className="w-full p-3 border border-gray-300 rounded-lg text-gray-900 bg-white focus:ring-2 focus:ring-blue-500" />
              </div>
              <div className="pt-4 border-t">
                 <button onClick={async () => { if(confirm('Are you sure you want to clear all data? This cannot be undone.')) { localStorage.clear(); window.location.reload(); } }} className="w-full py-3 text-red-600 border border-red-200 rounded-lg hover:bg-red-50 transition-colors font-medium">Reset All App Data</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export type InvoiceStatus = 'overdue' | 'pending' | 'upcoming' | 'paid' | 'disputed';
export type MessageTone = 'friendly' | 'firm' | 'urgent' | 'final' | 'balanced';

export interface Message {
  date: string;
  type: MessageTone;
  sent: boolean;
}

export interface Invoice {
  id: number;
  clientName: string;
  amount: number;
  dueDate: string;
  clientPhone: string;
  invoiceNumber: string;
  status: InvoiceStatus;
  remindersSent: number;
  messages: Message[];
  createdAt: string;
  paidDate?: string;
  paidAmount?: number;
  paymentMethod?: string;
  paymentNotes?: string;
  lastReminder?: string;
}

export interface Settings {
  businessName: string;
  businessEmail: string;
  currency: string;
  messageStyle: MessageTone;
  firstReminderDays: number;
  escalationDays: number;
  workingHoursOnly: boolean;
  pauseWeekends: boolean;
  whatsappConnected: boolean;
  autoSend: boolean;
}

export interface TeamMember {
  id: number;
  name: string;
  email: string;
  role: string;
  avatar: string;
}

export interface Analytics {
  totalRecovered: number;
  totalOutstanding: number;
  overdueAmount: number;
  thisMonthRecovered: number;
  averageDaysToPayment: number;
  successRate: number;
}

import React, { useState, useEffect, useCallback } from 'react';
import { 
  DollarSign, Clock, CheckCircle, AlertCircle, Send, Plus, ArrowLeft, 
  Calendar, User, FileText, MessageSquare, Camera, X, Check, Settings as SettingsIcon, 
  CreditCard, PauseCircle, Edit3, Bell, Smartphone, Building, Share2, Mail, 
  Download, ChevronRight, Zap, Shield, TrendingUp, Users, Link2, QrCode, 
  PhoneCall, BarChart3, TrendingDown, Copy, CheckCheck, Wifi, WifiOff, Trash2,
  Settings2, Info, BellRing, History
} from 'lucide-react';
import { 
  Invoice, Message, Settings, TeamMember, Analytics, 
  InvoiceStatus, MessageTone 
} from './types';

interface StorageResult {
  value: string;
}

const messageTemplates: Record<string, { title: string; example: string }> = {
  friendly: {
    title: "Friendly Reminder",
    example: "Hi {name}! 👋 Just a gentle reminder that invoice #{number} for R{amount} was due on {date}. When can we expect payment? Let me know if you need the invoice resent. Thanks!"
  },
  firm: {
    title: "Firm Follow-up",
    example: "Hi {name}, invoice #{number} for R{amount} is now {days} days overdue. Please arrange payment this week. If there's an issue, let's discuss. Payment details attached."
  },
  urgent: {
    title: "Urgent Notice",
    example: "{name}, invoice #{number} (R{amount}) remains unpaid after {days} days. This is affecting our cashflow. Please prioritize payment immediately or contact me today to arrange a plan."
  },
  final: {
    title: "Final Notice",
    example: "{name}, FINAL NOTICE: Invoice #{number} for R{amount} is {days} days overdue. Payment must be received within 48 hours to avoid further action. Contact me urgently if there are any issues."
  }
};

export default function DebtChaser() {
  const [loading, setLoading] = useState(true);
  const [selectedInvoiceId, setSelectedInvoiceId] = useState<number | null>(null);
  const [showUpload, setShowUpload] = useState(false);
  const [showSendConfirm, setShowSendConfirm] = useState(false);
  const [showPaymentLog, setShowPaymentLog] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [hasSeenOnboarding, setHasSeenOnboarding] = useState(false);

  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [settings, setSettings] = useState<Settings>({
    businessName: "Your Business",
    businessEmail: "",
    currency: "R",
    messageStyle: "balanced" as any,
    firstReminderDays: 2,
    escalationDays: 3,
    workingHoursOnly: true,
    pauseWeekends: false,
    whatsappConnected: true,
    autoSend: false
  });

  const loadData = useCallback(async () => {
    try {
      const storage = (window as any).storage;
      const invoicesResult: StorageResult | null = await storage.get('invoices');
      if (invoicesResult) setInvoices(JSON.parse(invoicesResult.value));

      const settingsResult: StorageResult | null = await storage.get('settings');
      if (settingsResult) setSettings(JSON.parse(settingsResult.value));

      const onboardingResult = await storage.get('onboarding_complete');
      setHasSeenOnboarding(!!onboardingResult);
    } catch (error) {
      console.error('Initialization error:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const saveInvoices = async (newInvoices: Invoice[]) => {
    setInvoices(newInvoices);
    await (window as any).storage.set('invoices', JSON.stringify(newInvoices));
  };

  const saveSettings = async (newSettings: Settings) => {
    setSettings(newSettings);
    await (window as any).storage.set('settings', JSON.stringify(newSettings));
  };

  const getInvoiceStatus = (dueDate: string): InvoiceStatus => {
    const today = new Date();
    today.setHours(0,0,0,0);
    const due = new Date(dueDate);
    due.setHours(0,0,0,0);
    const diffDays = Math.ceil((due.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    if (diffDays < 0) return 'overdue';
    if (diffDays <= 3) return 'pending';
    return 'upcoming';
  };

  const getDaysOverdue = (dueDate: string) => {
    const today = new Date();
    today.setHours(0,0,0,0);
    const due = new Date(dueDate);
    due.setHours(0,0,0,0);
    const diffDays = Math.ceil((today.getTime() - due.getTime()) / (1000 * 60 * 60 * 24));
    return diffDays > 0 ? diffDays : 0;
  };

  const addInvoice = async (invoiceData: Partial<Invoice>) => {
    const newInvoice: Invoice = {
      id: Date.now(),
      clientName: invoiceData.clientName || '',
      amount: invoiceData.amount || 0,
      dueDate: invoiceData.dueDate || '',
      clientPhone: invoiceData.clientPhone || '',
      invoiceNumber: invoiceData.invoiceNumber || '',
      status: getInvoiceStatus(invoiceData.dueDate || ''),
      remindersSent: 0,
      messages: [],
      createdAt: new Date().toISOString()
    };
    const updated = [...invoices, newInvoice];
    await saveInvoices(updated);
    return newInvoice;
  };

  const updateInvoice = async (id: number, updates: Partial<Invoice>) => {
    const updated = invoices.map(inv => inv.id === id ? { ...inv, ...updates } : inv);
    await saveInvoices(updated);
  };

  const deleteInvoice = async (id: number) => {
    const updated = invoices.filter(inv => inv.id !== id);
    await saveInvoices(updated);
  };

  const markAsPaid = async (id: number, paymentData: { date: string; amount: number; method: string; notes: string }) => {
    await updateInvoice(id, {
