  };

  const sendReminder = async (id: number, messageType: MessageTone) => {
    const invoice = invoices.find(inv => inv.id === id);
    if (!invoice) return;
    const newMessage: Message = { date: new Date().toISOString(), type: messageType, sent: true };
    await updateInvoice(id, {
      messages: [...invoice.messages, newMessage],
      remindersSent: invoice.remindersSent + 1,
      lastReminder: new Date().toISOString()
    });
  };

  const analytics: Analytics = {
    totalRecovered: invoices.filter(inv => inv.status === 'paid').reduce((sum, inv) => sum + (inv.paidAmount || inv.amount), 0),
    totalOutstanding: invoices.filter(inv => inv.status !== 'paid').reduce((sum, inv) => sum + inv.amount, 0),
    overdueAmount: invoices.filter(inv => inv.status === 'overdue').reduce((sum, inv) => sum + inv.amount, 0),
    thisMonthRecovered: invoices.filter(inv => {
      if (inv.status !== 'paid' || !inv.paidDate) return false;
      const d = new Date(inv.paidDate);
      const now = new Date();
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    }).reduce((sum, inv) => sum + (inv.paidAmount || inv.amount), 0),
    averageDaysToPayment: (() => {
      const paid = invoices.filter(inv => inv.status === 'paid' && inv.paidDate);
      if (paid.length === 0) return 0;
      const days = paid.reduce((sum, inv) => {
        const diff = new Date(inv.paidDate!).getTime() - new Date(inv.dueDate).getTime();
        return sum + Math.ceil(diff / (1000 * 60 * 60 * 24));
      }, 0);
      return Math.round(days / paid.length);
    })(),
    successRate: invoices.length > 0 ? Math.round((invoices.filter(inv => inv.status === 'paid').length / invoices.length) * 100) : 0
