              <button onClick={() => setShowSendConfirm(false)} className="flex-1 py-4 font-bold text-slate-400">Back</button>
              <button 
                onClick={async () => { await sendReminder(selectedInvoiceId, 'friendly'); setShowSendConfirm(false); }} 
                className="flex-[2] py-4 bg-[#25D366] text-white rounded-2xl font-black shadow-lg shadow-green-100 flex items-center justify-center gap-2"
              >
                Confirm & Send
              </button>
            </div>
          </div>
        </div>
      )}
      {showPaymentLog && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[32px] w-full max-w-sm p-8 shadow-2xl text-center">
            <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center mx-auto mb-6">
              <CheckCircle className="w-10 h-10" />
            </div>
            <h3 className="font-black text-2xl text-slate-900 mb-2">Record Payment</h3>
            <p className="text-slate-400 mb-8 font-medium">Mark this invoice as fully paid? This will stop all reminders.</p>
            <div className="flex gap-3">
              <button onClick={() => setShowPaymentLog(false)} className="flex-1 py-4 text-slate-400 font-bold">Cancel</button>
              <button 
                onClick={async () => { await markAsPaid(selectedInvoiceId, { date: new Date().toISOString(), amount: 0, method: 'Manual', notes: '' }); setShowPaymentLog(false); }} 
                className="flex-[2] py-4 bg-emerald-600 text-white rounded-2xl font-black shadow-lg shadow-emerald-100"
              >
                Yes, Paid
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );

  return (
    <div className="min-h-screen bg-slate-50 pb-32">
      <div className="bg-white border-b sticky top-0 z-10 px-4 py-4">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-slate-900 text-white p-2 rounded-xl">
              <Zap className="w-5 h-5 fill-current" />
            </div>
            <div>
              <h1 className="text-xl font-black text-slate-900 tracking-tighter">DEBT CHASER</h1>
              <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest">{settings.businessName}</p>
            </div>
          </div>
          <button onClick={() => setShowSettings(true)} className="p-2.5 bg-slate-50 hover:bg-slate-100 rounded-2xl transition-colors">
            <SettingsIcon className="w-6 h-6 text-slate-400" />
          </button>
        </div>
      </div>

      <main className="max-w-4xl mx-auto px-4 py-8 space-y-8">
        {invoices.length > 0 && (
          <div className="bg-slate-900 rounded-[32px] p-8 text-white shadow-2xl relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-8 opacity-10 transform group-hover:scale-110 transition-transform duration-1000">
              <TrendingUp className="w-48 h-48" />
            </div>
            <div className="relative z-10 grid md:grid-cols-2 gap-8 items-center">
              <div>
                <p className="text-slate-400 text-sm font-bold uppercase tracking-widest mb-1">Total Recovered</p>
                <p className="text-5xl font-black tracking-tighter mb-4">R{analytics.totalRecovered.toLocaleString()}</p>
                <div className="flex items-center gap-4">
                  <span className="bg-emerald-500/20 text-emerald-400 px-3 py-1 rounded-full text-xs font-black uppercase tracking-widest">
                    {analytics.successRate}% Success
                  </span>
                  <span className="text-slate-500 text-xs font-bold uppercase tracking-widest">
                    {analytics.averageDaysToPayment}d Avg Pay
                  </span>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="bg-white/5 border border-white/10 p-5 rounded-3xl">
                  <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mb-1">Outstanding</p>
                  <p className="text-xl font-black">R{analytics.totalOutstanding.toLocaleString()}</p>
                </div>
                <div className="bg-red-500/5 border border-red-500/10 p-5 rounded-3xl">
                  <p className="text-red-400/60 text-[10px] font-black uppercase tracking-widest mb-1">Overdue</p>
                  <p className="text-xl font-black text-red-400">R{analytics.overdueAmount.toLocaleString()}</p>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="space-y-4">
          <div className="flex items-center justify-between px-2">
            <h2 className="font-black text-slate-900 uppercase tracking-widest text-xs flex items-center gap-2">
              <History className="w-4 h-4 text-slate-400" />
              Recent Receivables
            </h2>
            <button onClick={() => setShowUpload(true)} className="text-blue-600 font-black text-xs uppercase tracking-widest hover:underline">
              View All
            </button>
          </div>

          {invoices.length === 0 ? (
            <div className="bg-white rounded-[32px] border border-gray-200 p-20 text-center shadow-sm">
              <div className="bg-slate-50 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-6">
                <FileText className="w-10 h-10 text-slate-200" />
              </div>
              <h3 className="text-xl font-black text-slate-900 mb-2">No invoices yet</h3>
              <p className="text-slate-400 font-medium mb-8 max-w-xs mx-auto">Start by adding your first invoice to recover that cash.</p>
              <button onClick={() => setShowUpload(true)} className="bg-blue-600 text-white px-10 py-4 rounded-2xl font-black shadow-xl shadow-blue-100 active:scale-95 transition-all">
                Add Invoice
              </button>
            </div>
          ) : (
            <div className="grid gap-4">
              {invoices.map(invoice => (
                <button 
                  key={invoice.id} 
                  onClick={() => setSelectedInvoiceId(invoice.id)} 
                  className="w-full bg-white rounded-3xl border border-gray-200 p-6 text-left hover:border-blue-400 transition-all group shadow-sm flex items-center gap-4"
                >
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-lg ${
                    invoice.status === 'paid' ? 'bg-emerald-50 text-emerald-600' : 
                    invoice.status === 'overdue' ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'
                  }`}>
                    {invoice.clientName.charAt(0)}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between">
                      <p className="font-black text-slate-900 group-hover:text-blue-600 transition-colors truncate">{invoice.clientName}</p>
                      <p className="font-black text-slate-900 ml-4">R{invoice.amount.toLocaleString()}</p>
                    </div>
                    <div className="flex items-center justify-between mt-1">
                      <span className={`text-[10px] font-black uppercase tracking-widest ${
                        invoice.status === 'paid' ? 'text-emerald-500' : 
                        invoice.status === 'overdue' ? 'text-red-500' : 'text-slate-400'
                      }`}>
                        {invoice.status} • {new Date(invoice.dueDate).toLocaleDateString('en-ZA')}
                      </span>
                      {invoice.remindersSent > 0 && (
                        <span className="bg-slate-50 px-2 py-0.5 rounded-lg text-[10px] font-black text-slate-400">
                          {invoice.remindersSent} RMD
                        </span>
                      )}
                    </div>
                  </div>
                  <ChevronRight className="w-5 h-5 text-slate-300 group-hover:translate-x-1 transition-transform" />
                </button>
              ))}
            </div>
          )}
        </div>
      </main>

      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-lg px-6">
        <button 
          onClick={() => setShowUpload(true)} 
          className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black flex items-center justify-center gap-3 shadow-2xl shadow-slate-200 active:scale-95 transition-all"
        >
          <Plus className="w-6 h-6" />
          Create New Invoice
        </button>
      </div>

      {showSettings && <SettingsModal />}
    </div>
  );
}

export type InvoiceStatus = 'overdue' | 'pending' | 'upcoming' | 'paid' | 'disputed';
export type MessageTone = 'friendly' | 'firm' | 'urgent' | 'final' | 'balanced';

export interface Message {
  date: string;
  type: MessageTone;
  sent: boolean;
}

export interface Invoice {
  id: number;
  clientName: string;
  amount: number;
  dueDate: string;
  clientPhone: string;
  invoiceNumber: string;
  status: InvoiceStatus;
  remindersSent: number;
  messages: Message[];
  createdAt: string;
  paidDate?: string;
  paidAmount?: number;
  paymentMethod?: string;
  paymentNotes?: string;
  lastReminder?: string;
}

export interface Settings {
  businessName: string;
  businessEmail: string;
  currency: string;
  messageStyle: MessageTone;
  firstReminderDays: number;
  escalationDays: number;
  workingHoursOnly: boolean;
  pauseWeekends: boolean;
  whatsappConnected: boolean;
  autoSend: boolean;
  language: string;
}

export interface Analytics {
  totalRecovered: number;
  totalOutstanding: number;
  overdueAmount: number;
  thisMonthRecovered: number;
  averageDaysToPayment: number;
  successRate: number;
}

import React, { useState, useEffect, useCallback } from 'react';
import { 
  DollarSign, Clock, CheckCircle, AlertCircle, Send, Plus, ArrowLeft, 
  Calendar, User, FileText, MessageSquare, Camera, X, Check, Settings as SettingsIcon, 
  PauseCircle, Download, ChevronRight, Zap, Shield, TrendingUp, BarChart3, 
  Trash2, Settings2, BellRing, History, Smartphone, Building, CheckCheck, 
  Globe, BadgeInfo, LogOut, HelpCircle
} from 'lucide-react';
import { 
  Invoice, Message, Settings, Analytics, 
  InvoiceStatus, MessageTone 
} from './types';

interface StorageResult {
  value: string;
}

const messageTemplates: Record<string, { title: string; example: string }> = {
  friendly: {
    title: "Friendly Reminder",
    example: "Hi {name}! 👋 Just a gentle reminder that invoice #{number} for {currency}{amount} was due on {date}. When can we expect payment? Let me know if you need the invoice resent. Thanks!"
  },
  firm: {
    title: "Firm Follow-up",
    example: "Hi {name}, invoice #{number} for {currency}{amount} is now {days} days overdue. Please arrange payment this week. If there's an issue, let's discuss. Payment details attached."
  }
};

export default function DebtChaser() {
  const [loading, setLoading] = useState(true);
  const [selectedInvoiceId, setSelectedInvoiceId] = useState<number | null>(null);
  const [showUpload, setShowUpload] = useState(false);
  const [showSendConfirm, setShowSendConfirm] = useState(false);
  const [showPaymentLog, setShowPaymentLog] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [hasSeenOnboarding, setHasSeenOnboarding] = useState(false);

  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [settings, setSettings] = useState<Settings>({
    businessName: "Your Business",
    businessEmail: "",
    currency: "R",
    messageStyle: "friendly",
    firstReminderDays: 2,
    escalationDays: 3,
    workingHoursOnly: true,
    pauseWeekends: false,
    whatsappConnected: true,
    autoSend: false,
    language: "English"
  });

  const loadData = useCallback(async () => {
    try {
      const storage = (window as any).storage;
      const invoicesResult: StorageResult | null = await storage.get('invoices');
      if (invoicesResult) setInvoices(JSON.parse(invoicesResult.value));

      const settingsResult: StorageResult | null = await storage.get('settings');
      if (settingsResult) setSettings(JSON.parse(settingsResult.value));

      const onboardingResult = await storage.get('onboarding_complete');
      setHasSeenOnboarding(!!onboardingResult);
    } catch (error) {
      console.error('Initialization error:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const saveInvoices = async (newInvoices: Invoice[]) => {
    setInvoices(newInvoices);
    await (window as any).storage.set('invoices', JSON.stringify(newInvoices));
  };

  const saveSettings = async (newSettings: Settings) => {
    setSettings(newSettings);
    await (window as any).storage.set('settings', JSON.stringify(newSettings));
  };

  const exportToCSV = () => {
    if (invoices.length === 0) return alert("No invoices to export.");
    const headers = ["ID", "Client", "Amount", "Due Date", "Status", "Reminders Sent"];
    const rows = invoices.map(i => [i.id, i.clientName, i.amount, i.dueDate, i.status, i.remindersSent]);
    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `debt_chaser_invoices_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const getInvoiceStatus = (dueDate: string): InvoiceStatus => {
    const today = new Date();
    today.setHours(0,0,0,0);
    const due = new Date(dueDate);
    due.setHours(0,0,0,0);
    const diffDays = Math.ceil((due.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    if (diffDays < 0) return 'overdue';
    if (diffDays <= 3) return 'pending';
    return 'upcoming';
  };

  const getDaysOverdue = (dueDate: string) => {
    const today = new Date();
    today.setHours(0,0,0,0);
    const due = new Date(dueDate);
    due.setHours(0,0,0,0);
    const diffDays = Math.ceil((today.getTime() - due.getTime()) / (1000 * 60 * 60 * 24));
    return diffDays > 0 ? diffDays : 0;
  };

  const addInvoice = async (invoiceData: Partial<Invoice>) => {
    const newInvoice: Invoice = {
      id: Date.now(),
      clientName: invoiceData.clientName || '',
      amount: invoiceData.amount || 0,
      dueDate: invoiceData.dueDate || '',
      clientPhone: invoiceData.clientPhone || '',
      invoiceNumber: invoiceData.invoiceNumber || '',
      status: getInvoiceStatus(invoiceData.dueDate || ''),
      remindersSent: 0,
      messages: [],
      createdAt: new Date().toISOString()
    };
    const updated = [...invoices, newInvoice];
    await saveInvoices(updated);
    return newInvoice;
  };

  const updateInvoice = async (id: number, updates: Partial<Invoice>) => {
    const updated = invoices.map(inv => inv.id === id ? { ...inv, ...updates } : inv);
    await saveInvoices(updated);
  };

  const deleteInvoice = async (id: number) => {
    const updated = invoices.filter(inv => inv.id !== id);
    await saveInvoices(updated);
  };

  const markAsPaid = async (id: number) => {
    await updateInvoice(id, {
      status: 'paid',
      paidDate: new Date().toISOString()
    });
  };

  const sendReminder = async (id: number, messageType: MessageTone) => {
    const invoice = invoices.find(inv => inv.id === id);
    if (!invoice || !settings.whatsappConnected) return;
    const newMessage: Message = { date: new Date().toISOString(), type: messageType, sent: true };
    await updateInvoice(id, {
      messages: [...invoice.messages, newMessage],
      remindersSent: invoice.remindersSent + 1,
      lastReminder: new Date().toISOString()
    });
  };

  const analytics: Analytics = {
    totalRecovered: invoices.filter(inv => inv.status === 'paid').reduce((sum, inv) => sum + inv.amount, 0),
    totalOutstanding: invoices.filter(inv => inv.status !== 'paid').reduce((sum, inv) => sum + inv.amount, 0),
    overdueAmount: invoices.filter(inv => inv.status === 'overdue').reduce((sum, inv) => sum + inv.amount, 0),
    thisMonthRecovered: invoices.filter(inv => {
      if (inv.status !== 'paid' || !inv.paidDate) return false;
      const d = new Date(inv.paidDate);
      const now = new Date();
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    }).reduce((sum, inv) => sum + inv.amount, 0),
    averageDaysToPayment: (() => {
      const paid = invoices.filter(inv => inv.status === 'paid' && inv.paidDate);
      if (paid.length === 0) return 0;
      const days = paid.reduce((sum, inv) => {
        const diff = new Date(inv.paidDate!).getTime() - new Date(inv.dueDate).getTime();
        return sum + Math.ceil(diff / (1000 * 60 * 60 * 24));
      }, 0);
      return Math.round(days / paid.length);
    })(),
    successRate: invoices.length > 0 ? Math.round((invoices.filter(inv => inv.status === 'paid').length / invoices.length) * 100) : 0
  };

  const getStatusColor = (status: InvoiceStatus) => {
    switch(status) {
      case 'overdue': return 'text-red-600 bg-red-50 border-red-100';
      case 'pending': return 'text-amber-600 bg-amber-50 border-amber-100';
      case 'paid': return 'text-emerald-600 bg-emerald-50 border-emerald-100';
      default: return 'text-blue-600 bg-blue-50 border-blue-100';
    }
  };

  const formatMessage = (template: string, invoice: Invoice) => {
    const days = getDaysOverdue(invoice.dueDate);
    return template
      .replace('{name}', invoice.clientName.split(" ")[0])
      .replace('{number}', invoice.invoiceNumber || `${invoice.id}`)
      .replace('{amount}', invoice.amount.toLocaleString())
      .replace('{currency}', settings.currency)
      .replace('{date}', new Date(invoice.dueDate).toLocaleDateString('en-ZA'))
      .replace('{days}', days.toString());
  };

  const inputClass = "w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-white text-gray-900 placeholder-gray-400 transition-all outline-none shadow-sm";

  const OnboardingFlow = () => {
    const [step, setStep] = useState(0);
    const steps = [
      {
        title: "Stop Chasing.",
        subtitle: "Start Collecting.",
        description: "Unpaid invoices are the silent killer of small businesses. Debt Chaser is your automated recovery partner.",
        icon: DollarSign,
        color: "blue"
      },
      {
        title: "Smart Automation.",
        subtitle: "WhatsApp Powered.",
        description: "Our engine sends perfectly timed reminders. Friendly at first, firm when needed. No manual typing required.",
        icon: MessageSquare,
        color: "emerald"
      },
      {
        title: "Crystal Clear.",
        subtitle: "Real-time Analytics.",
        description: "See exactly who owes you what, how long they've been dodging, and your total recovery rate at a glance.",
        icon: TrendingUp,
        color: "purple"
      }
    ];

    const currentStep = steps[step];
    const isLastStep = step === steps.length - 1;

    return (
      <div className="fixed inset-0 bg-slate-950 z-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-[40px] w-full max-w-md overflow-hidden shadow-2xl relative">
          <div className="h-1.5 w-full flex gap-1 px-10 pt-10">
            {steps.map((_, i) => (
              <div key={i} className={`h-1 flex-1 rounded-full transition-all duration-700 ${i <= step ? 'bg-blue-600' : 'bg-gray-100'}`} />
            ))}
          </div>
          <div className="p-12 text-center">
            <div className={`inline-flex items-center justify-center w-28 h-28 rounded-[32px] mb-10 transform transition-transform duration-700 hover:scale-105 ${
              currentStep.color === 'blue' ? 'bg-blue-50 text-blue-600' :
              currentStep.color === 'emerald' ? 'bg-emerald-50 text-emerald-600' :
              'bg-purple-50 text-purple-600'
            }`}>
              <currentStep.icon className="w-14 h-14" />
            </div>
            <h2 className="text-4xl font-black text-slate-900 mb-2 leading-tight tracking-tight">{currentStep.title}</h2>
            <p className="text-blue-600 font-bold mb-8 uppercase tracking-widest text-xs">{currentStep.subtitle}</p>
            <p className="text-slate-500 leading-relaxed mb-12 font-medium">{currentStep.description}</p>

            <div className="space-y-4">
              <button
                onClick={async () => {
                  if (isLastStep) {
                    await (window as any).storage.set('onboarding_complete', 'true');
                    setHasSeenOnboarding(true);
                  } else {
                    setStep(step + 1);
                  }
                }}
                className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-2 shadow-2xl shadow-slate-200"
              >
                {isLastStep ? "Enter Dashboard" : "Next Step"}
                <ChevronRight className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  const SettingsModal = () => {
    return (
      <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center p-4">
        <div className="bg-gray-50 rounded-[36px] w-full max-w-lg overflow-hidden shadow-2xl flex flex-col max-h-[85vh] border border-white/20">
          <div className="px-8 py-8 bg-white border-b flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="bg-blue-600 p-2.5 rounded-2xl text-white shadow-lg shadow-blue-200">
                <Settings2 className="w-6 h-6" />
              </div>
              <div>
                <h3 className="font-black text-2xl text-slate-900 leading-none">Settings</h3>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase tracking-widest">Configuration Panel</p>
              </div>
            </div>
            <button onClick={() => setShowSettings(false)} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
              <X className="w-7 h-7 text-gray-400" />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-8 space-y-10">
            {/* Category: Business */}
            <section className="space-y-5">
              <h4 className="flex items-center gap-2 text-slate-400 font-black text-[11px] uppercase tracking-[0.2em] px-1">
                <Building className="w-4 h-4" />
                Profile & Identity
              </h4>
              <div className="bg-white rounded-3xl p-6 border border-gray-200 space-y-5 shadow-sm">
                <div>
                  <label className="block text-xs font-black text-slate-500 mb-2 uppercase tracking-wider">Business Name</label>
                  <input type="text" value={settings.businessName} onChange={e => saveSettings({...settings, businessName: e.target.value})} className={inputClass} />
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-500 mb-2 uppercase tracking-wider">Billing Email</label>
                  <input type="email" value={settings.businessEmail} onChange={e => saveSettings({...settings, businessEmail: e.target.value})} className={inputClass} placeholder="accounts@company.com" />
                </div>
              </div>
            </section>

            {/* Category: Regional */}
            <section className="space-y-5">
              <h4 className="flex items-center gap-2 text-slate-400 font-black text-[11px] uppercase tracking-[0.2em] px-1">
                <Globe className="w-4 h-4" />
                Regional & Localization
              </h4>
              <div className="bg-white rounded-3xl p-6 border border-gray-200 grid grid-cols-2 gap-4 shadow-sm">
                <div>
                  <label className="block text-xs font-black text-slate-500 mb-2 uppercase tracking-wider">Currency</label>
                  <select value={settings.currency} onChange={e => saveSettings({...settings, currency: e.target.value})} className={inputClass}>
                    <option value="R">R (ZAR)</option>
                    <option value="$">$ (USD)</option>
                    <option value="£">£ (GBP)</option>
                    <option value="€">€ (EUR)</option>
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-black text-slate-500 mb-2 uppercase tracking-wider">Language</label>
                  <select value={settings.language} onChange={e => saveSettings({...settings, language: e.target.value})} className={inputClass}>
                    <option>English</option>
                    <option>Afrikaans</option>
                    <option>Zulu</option>
                  </select>
                </div>
              </div>
            </section>

            {/* Category: Automation */}
            <section className="space-y-5">
              <h4 className="flex items-center gap-2 text-slate-400 font-black text-[11px] uppercase tracking-[0.2em] px-1">
                <Zap className="w-4 h-4" />
                Automation Engine
              </h4>
              <div className="bg-white rounded-3xl p-6 border border-gray-200 space-y-6 shadow-sm">
