              </div>
            </section>

            <div className="text-center pt-4 pb-8 opacity-20">
              <p className="text-[9px] font-black uppercase tracking-[0.4em]">Encrypted Local Storage • No Cloud Sync</p>
            </div>
          </div>
        </div>
      </div>
