          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight leading-none">New Receivable</h1>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Invoice Data Entry</p>
          </div>
        </div>
        <div className="max-w-2xl mx-auto px-8 py-10 space-y-10">
          <div className="space-y-8">
            <div className="grid gap-8">
              <div className="space-y-3">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">Client / Business Name</label>
