  const WhatsAppMessage: React.FC<{ message: string; sent?: boolean }> = ({ message, sent = true }) => (
    <div className={`flex ${sent ? 'justify-end' : 'justify-start'} mb-4`}>
      <div className={`max-w-[90%] rounded-3xl px-5 py-4 shadow-sm ${
        sent ? 'bg-[#DCF8C6] text-slate-900' : 'bg-white text-slate-900 border border-slate-100'
