            <button onClick={async () => { if(confirm('Delete permanently?')) { await deleteInvoice(invoice.id); setSelectedInvoiceId(null); }}} className="p-3 bg-red-50 text-red-500 hover:bg-red-100 rounded-2xl transition-colors">
              <Trash2 className="w-5 h-5" />
