        </div>

        <div className="max-w-2xl mx-auto px-6 py-8 space-y-8">
          <div className="bg-white rounded-[40px] border border-gray-200 p-10 shadow-sm relative overflow-hidden">
            <div className="flex flex-col items-center text-center">
              <span className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.1em] border-2 ${getStatusColor(invoice.status)}`}>
