              <p className="text-6xl font-black text-slate-900 mt-6 mb-2 tracking-tighter">{settings.currency}{invoice.amount.toLocaleString()}</p>
              <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Due {new Date(invoice.dueDate).toLocaleDateString('en-ZA', { day: 'numeric', month: 'short' })}</p>
