                    <MessageSquare className="w-12 h-12 mx-auto mb-4" />
                    <p className="text-slate-900 font-black text-xs uppercase tracking-widest">Awaiting First Reminder</p>
                  </div>
                ) : (
                  invoice.messages.map((msg, idx) => (
                    <div key={idx} className="space-y-4">
                      <div className="flex items-center gap-3">
                        <div className="h-px flex-1 bg-slate-100" />
                        <span className="text-[9px] font-black text-slate-300 uppercase tracking-[0.3em]">
                          {new Date(msg.date).toLocaleDateString('en-ZA', { day: '2-digit', month: 'short' })}
