          {invoice.status !== 'paid' && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-2xl px-6 flex gap-4">
              <button 
                onClick={() => settings.whatsappConnected ? setShowSendConfirm(true) : alert("WhatsApp Engine is disconnected in Settings.")} 
                className={`flex-[2] py-5 rounded-2xl font-black text-lg flex items-center justify-center gap-3 shadow-2xl transition-all active:scale-95 ${
