              <button 
                onClick={() => setShowPaymentLog(true)} 
                className="flex-1 bg-white text-slate-900 border-4 border-slate-900 py-5 rounded-2xl font-black text-lg flex items-center justify-center gap-3 active:scale-95 transition-all"
              >
                <CheckCircle className="w-6 h-6" /> Paid
              </button>
            </div>
          )}
        </div>
      </div>
    );
  };

  if (loading) return <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center space-y-6 font-black text-slate-300 uppercase tracking-widest text-[10px]"><Zap className="w-12 h-12 animate-pulse text-blue-600" />System Initializing...</div>;
  if (!hasSeenOnboarding) return <OnboardingFlow />;
  if (showUpload) return <UploadFlow />;
  if (selectedInvoiceId) return (
    <>
      <InvoiceDetail />
      {showSendConfirm && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-end sm:items-center justify-center p-6">
          <div className="bg-white rounded-[40px] w-full max-w-lg p-10 shadow-2xl border border-white/20">
            <h3 className="font-black text-3xl text-slate-900 mb-8 flex items-center gap-4 leading-none">
