               <div className="absolute top-0 right-0 p-4 opacity-5"><MessageSquare className="w-20 h-20" /></div>
              <WhatsAppMessage message={formatMessage(messageTemplates[settings.messageStyle]?.example || messageTemplates.friendly.example, invoices.find(i => i.id === selectedInvoiceId)!)} />
            </div>
            <div className="flex gap-4">
              <button onClick={() => setShowSendConfirm(false)} className="flex-1 py-5 font-black text-slate-400 uppercase tracking-widest text-xs">Cancel</button>
              <button 
                onClick={async () => { await sendReminder(selectedInvoiceId, settings.messageStyle); setShowSendConfirm(false); }} 
                className="flex-[2] py-5 bg-[#25D366] text-white rounded-2xl font-black text-lg shadow-xl shadow-green-100 flex items-center justify-center gap-3"
