            <span className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border-2 ${getStatusColor(invoice.status)}`}>
              {invoice.status === 'overdue' ? `🚨 ${days}D DELAYED` : invoice.status}
