                    <p className="font-black text-xl text-slate-900 tracking-tight truncate">{invoice.clientName}</p>
                    <div className="flex items-center gap-2 mt-2">
                      <span className={`text-[10px] font-black uppercase px-2 py-0.5 rounded border ${getStatusColor(invoice.status)}`}>
                        {invoice.status}
                      </span>
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                        {new Date(invoice.dueDate).toLocaleDateString('en-ZA')}
                      </span>
                    </div>
                  </div>
                  <p className="font-black text-xl text-slate-900 tracking-tighter ml-4">{settings.currency}{invoice.amount.toLocaleString()}</p>
                </button>
              ))}
            </div>
          )}
        </div>
      </main>

      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 w-full max-w-lg px-8">
        <button 
          onClick={() => setShowUpload(true)} 
          className="w-full bg-slate-900 text-white py-6 rounded-[28px] font-black text-xl flex items-center justify-center gap-4 shadow-3xl active:scale-95 border-4 border-white"
        >
          <Plus className="w-7 h-7" />
          Track New Invoice
        </button>
      </div>

      {showSettings && <SettingsModal />}
      {showUpload && <UploadFlow />}
      {selectedInvoiceId && <InvoiceDetail />}

      {/* DELETE CONFIRMATION MODAL */}
      {showDeleteConfirm && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[100] flex items-center justify-center p-6">
          <div className="bg-white rounded-[40px] w-full max-w-sm p-10 shadow-2xl text-center border border-white/20">
            <div className="w-24 h-24 bg-red-50 text-red-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 animate-pulse">
              <AlertCircle className="w-12 h-12" />
            </div>
            <h3 className="font-black text-3xl text-slate-900 mb-2">Delete Entry?</h3>
            <p className="text-slate-400 mb-10 font-bold uppercase tracking-widest text-[10px]">This action cannot be undone.</p>
            <div className="flex gap-4">
              <button onClick={() => setShowDeleteConfirm(false)} className="flex-1 py-4 text-slate-400 font-black text-xs">Cancel</button>
              <button 
                onClick={async () => { await deleteInvoice(selectedInvoiceId!); }} 
                className="flex-[2] py-4 bg-red-600 text-white rounded-2xl font-black text-lg shadow-xl active:scale-95"
              >
                Delete
              </button>
            </div>
          </div>
        </div>
      )}

      {showSendConfirm && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[100] flex items-end sm:items-center justify-center p-6">
          <div className="bg-white rounded-[40px] w-full max-w-lg p-10 shadow-2xl border border-white/20">
            <h3 className="font-black text-3xl text-slate-900 mb-8 flex items-center gap-4">
              <BellRing className="w-8 h-8 text-emerald-500" />
              Copy Text
            </h3>
            <div className="bg-[#ECE5DD] rounded-[32px] p-8 mb-10 border border-emerald-50 relative">
              <WhatsAppMessage message={formatMessage(messageTemplates[settings.messageStyle]?.example || messageTemplates.friendly.example, invoices.find(i => i.id === selectedInvoiceId)!)} />
            </div>
            <div className="flex gap-4">
              <button onClick={() => setShowSendConfirm(false)} className="flex-1 py-5 font-black text-slate-400 uppercase text-xs">Back</button>
              <button 
                onClick={async () => { 
                  const inv = invoices.find(i => i.id === selectedInvoiceId)!;
                  const text = formatMessage(messageTemplates[settings.messageStyle]?.example || messageTemplates.friendly.example, inv);
                  await copyToClipboard(text);
                  await recordReminderSent(selectedInvoiceId, settings.messageStyle);
                  setShowSendConfirm(false);
                }} 
                className="flex-[2] py-5 bg-slate-900 text-white rounded-2xl font-black text-lg active:scale-95"
              >
                Copy & Log
              </button>
            </div>
          </div>
        </div>
      )}

      {showPaymentLog && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[100] flex items-center justify-center p-6">
          <div className="bg-white rounded-[40px] w-full max-w-sm p-10 shadow-2xl text-center border border-white/20">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-600 rounded-[32px] flex items-center justify-center mx-auto mb-8">
              <CheckCircle className="w-12 h-12" />
            </div>
            <h3 className="font-black text-3xl text-slate-900 mb-2">Close Record?</h3>
            <p className="text-slate-400 mb-10 font-bold uppercase tracking-widest text-[10px]">Mark as fully settled</p>
            <div className="flex gap-4">
              <button onClick={() => setShowPaymentLog(false)} className="flex-1 py-4 text-slate-400 font-black text-xs">No</button>
              <button 
                onClick={async () => { await markAsPaid(selectedInvoiceId!); setShowPaymentLog(false); }} 
                className="flex-[2] py-4 bg-emerald-600 text-white rounded-2xl font-black text-lg shadow-xl"
              >
                Yes, Paid
              </button>
            </div>
          </div>
        </div>
      )}

      {copySuccess && (
        <div className="fixed bottom-32 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-8 py-4 rounded-2xl font-black text-sm shadow-2xl z-[200] animate-bounce">
          ✓ Copied to Clipboard
        </div>
      )}
    </div>
  );
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

// Professional Storage Abstraction
const storage = {
  get: async (key: string) => {
    try {
      const val = localStorage.getItem(key);
      return val ? { value: val } : null;
    } catch (e) {
      console.error("Storage read error:", e);
      return null;
    }
  },
  set: async (key: string, value: string) => {
    try {
      localStorage.setItem(key, value);
    } catch (e) {
      console.error("Storage write error:", e);
    }
  },
  delete: async (key: string) => {
    localStorage.removeItem(key);
  },
  clear: async () => {
    localStorage.clear();
  }
};

(window as any).storage = storage;

const rootElement = document.getElementById('root');
if (rootElement) {
  const root = ReactDOM.createRoot(rootElement);
  root.render(
    <React.StrictMode>
      <App />
    </React.StrictMode>
  );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  DollarSign, Clock, CheckCircle, AlertCircle, Send, Plus, ArrowLeft, 
  Calendar, User, FileText, MessageSquare, Camera, X, Check, Settings as SettingsIcon, 
  PauseCircle, Download, ChevronRight, Zap, Shield, TrendingUp, BarChart3, 
  Trash2, Settings2, BellRing, History, Smartphone, Building, CheckCheck, 
  Globe, BadgeInfo, LogOut, HelpCircle, Copy, ExternalLink
} from 'lucide-react';
import { 
  Invoice, Message, Settings, Analytics, 
  InvoiceStatus, MessageTone 
} from './types';

interface StorageResult {
  value: string;
}

const messageTemplates: Record<string, { title: string; example: string }> = {
  friendly: {
    title: "Friendly Reminder",
    example: "Hi {name}! 👋 Just a gentle reminder that invoice #{number} for {currency}{amount} was due on {date}. When can we expect payment? Let me know if you need the invoice resent. Thanks!"
  },
  firm: {
    title: "Firm Follow-up",
    example: "Hi {name}, invoice #{number} for {currency}{amount} is now {days} days overdue. Please arrange payment this week. If there's an issue, let's discuss. Payment details attached."
  }
};

export default function DebtChaser() {
  const [loading, setLoading] = useState(true);
  const [selectedInvoiceId, setSelectedInvoiceId] = useState<number | null>(null);
  const [showUpload, setShowUpload] = useState(false);
  const [showSendConfirm, setShowSendConfirm] = useState(false);
  const [showPaymentLog, setShowPaymentLog] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [hasSeenOnboarding, setHasSeenOnboarding] = useState(false);
  const [copySuccess, setCopySuccess] = useState(false);
  const [isResetting, setIsResetting] = useState(false);

  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [settings, setSettings] = useState<Settings>({
    businessName: "Your Business",
    businessEmail: "",
    currency: "R",
    messageStyle: "friendly",
    firstReminderDays: 2,
    escalationDays: 3,
    workingHoursOnly: true,
    pauseWeekends: false,
    whatsappConnected: true,
    autoSend: false,
    language: "English"
  });

  const loadData = useCallback(async () => {
    try {
      const storage = (window as any).storage;
      const invoicesResult: StorageResult | null = await storage.get('invoices');
      if (invoicesResult && invoicesResult.value) setInvoices(JSON.parse(invoicesResult.value));

      const settingsResult: StorageResult | null = await storage.get('settings');
      if (settingsResult && settingsResult.value) setSettings(JSON.parse(settingsResult.value));

      const onboardingResult = await storage.get('onboarding_complete');
      setHasSeenOnboarding(!!onboardingResult);
    } catch (error) {
      console.error('Initialization error:', error);
    } finally {
      // Small artificial delay to ensure DOM is ready for Vercel builds
      setTimeout(() => setLoading(false), 200);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  // WRAPPER: Only save if we aren't in the middle of a reset
  const saveInvoices = async (newInvoices: Invoice[]) => {
    if (isResetting) return;
    setInvoices(newInvoices);
    await (window as any).storage.set('invoices', JSON.stringify(newInvoices));
  };

  const saveSettings = async (newSettings: Settings) => {
    if (isResetting) return;
    setSettings(newSettings);
    await (window as any).storage.set('settings', JSON.stringify(newSettings));
  };

  const handleReset = async () => {
    if (!confirm('⚠️ PERMANENT: Delete all data? This cannot be undone.')) return;

    setIsResetting(true);
    const storage = (window as any).storage;

    try {
      // 1. Immediately clear the JS references to data
      setInvoices([]);
      setHasSeenOnboarding(false);

      // 2. Wipe the physical storage
      if (storage.clear) {
        await storage.clear();
      } else {
        await Promise.all([
          storage.delete('invoices'),
          storage.delete('settings'),
          storage.delete('onboarding_complete')
        ]);
      }

      // 3. Physical delay before reload to prevent "Ghost Saving" race conditions
      setTimeout(() => {
        window.location.replace(window.location.origin);
      }, 1000);
    } catch (err) {
      console.error("System Reset Failed:", err);
      setIsResetting(false);
    }
  };

  const exportToCSV = () => {
    if (invoices.length === 0) return alert("No invoices to export.");
    const headers = ["ID", "Client", "Amount", "Due Date", "Status", "Reminders Sent"];
    const rows = invoices.map(i => [
      i.id, 
      `"${i.clientName.replace(/"/g, '""')}"`, 
      i.amount, 
      i.dueDate, 
      i.status, 
      i.remindersSent
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `debt_chaser_export_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const getInvoiceStatus = (dueDate: string): InvoiceStatus => {
    const today = new Date();
    today.setHours(0,0,0,0);
    const due = new Date(dueDate);
    due.setHours(0,0,0,0);
    const diffDays = Math.ceil((due.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    if (diffDays < 0) return 'overdue';
    if (diffDays <= 3) return 'pending';
    return 'upcoming';
  };

  const getDaysOverdue = (dueDate: string) => {
    const today = new Date();
    today.setHours(0,0,0,0);
    const due = new Date(dueDate);
    due.setHours(0,0,0,0);
    const diffDays = Math.ceil((today.getTime() - due.getTime()) / (1000 * 60 * 60 * 24));
    return diffDays > 0 ? diffDays : 0;
  };

  const addInvoice = async (invoiceData: Partial<Invoice>) => {
    const newInvoice: Invoice = {
      id: Date.now(),
      clientName: invoiceData.clientName || '',
      amount: Number(invoiceData.amount) || 0,
      dueDate: invoiceData.dueDate || '',
      clientPhone: invoiceData.clientPhone || '',
      invoiceNumber: invoiceData.invoiceNumber || '',
      status: getInvoiceStatus(invoiceData.dueDate || ''),
      remindersSent: 0,
      messages: [],
      createdAt: new Date().toISOString()
    };
    const updated = [...invoices, newInvoice];
    await saveInvoices(updated);
  };

  const deleteInvoice = async (id: number) => {
    const updated = invoices.filter(inv => inv.id !== id);
    await saveInvoices(updated);
    setShowDeleteConfirm(false);
    setSelectedInvoiceId(null); 
  };

  const markAsPaid = async (id: number) => {
    const updated = invoices.map(inv => inv.id === id ? { 
      ...inv, 
      status: 'paid' as InvoiceStatus, 
      paidDate: new Date().toISOString() 
    } : inv);
    await saveInvoices(updated);
  };

  const recordReminderSent = async (id: number, messageType: MessageTone) => {
    const updated = invoices.map(inv => inv.id === id ? {
      ...inv,
      messages: [...inv.messages, { date: new Date().toISOString(), type: messageType, sent: true }],
      remindersSent: inv.remindersSent + 1,
      lastReminder: new Date().toISOString()
    } : inv);
    await saveInvoices(updated);
  };

  const analytics: Analytics = {
    totalRecovered: invoices.filter(inv => inv.status === 'paid').reduce((sum, inv) => sum + inv.amount, 0),
    totalOutstanding: invoices.filter(inv => inv.status !== 'paid').reduce((sum, inv) => sum + inv.amount, 0),
    overdueAmount: invoices.filter(inv => inv.status === 'overdue').reduce((sum, inv) => sum + inv.amount, 0),
    thisMonthRecovered: invoices.filter(inv => {
      if (inv.status !== 'paid' || !inv.paidDate) return false;
      const d = new Date(inv.paidDate);
      const now = new Date();
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    }).reduce((sum, inv) => sum + inv.amount, 0),
    averageDaysToPayment: (() => {
      const paid = invoices.filter(inv => inv.status === 'paid' && inv.paidDate);
      if (paid.length === 0) return 0;
      const days = paid.reduce((sum, inv) => {
        const diff = new Date(inv.paidDate!).getTime() - new Date(inv.dueDate).getTime();
        return sum + Math.ceil(diff / (1000 * 60 * 60 * 24));
      }, 0);
      return Math.round(days / paid.length);
    })(),
    successRate: invoices.length > 0 ? Math.round((invoices.filter(inv => inv.status === 'paid').length / invoices.length) * 100) : 0
  };

  const getStatusColor = (status: InvoiceStatus) => {
    switch(status) {
      case 'overdue': return 'text-red-600 bg-red-50 border-red-100';
      case 'pending': return 'text-amber-600 bg-amber-50 border-amber-100';
      case 'paid': return 'text-emerald-600 bg-emerald-50 border-emerald-100';
      default: return 'text-blue-600 bg-blue-50 border-blue-100';
    }
  };

  const formatMessage = (template: string, invoice: Invoice) => {
    const days = getDaysOverdue(invoice.dueDate);
    return template
      .replace('{name}', invoice.clientName.split(" ")[0])
      .replace('{number}', invoice.invoiceNumber || `${invoice.id}`)
      .replace('{amount}', invoice.amount.toLocaleString())
      .replace('{currency}', settings.currency)
      .replace('{date}', new Date(invoice.dueDate).toLocaleDateString('en-ZA'))
      .replace('{days}', days.toString());
  };

  const copyToClipboard = async (text: string) => {
    try {
      await navigator.clipboard.writeText(text);
      setCopySuccess(true);
      setTimeout(() => setCopySuccess(false), 2000);
    } catch (err) {
      alert("Clipboard access denied. Please copy manually.");
    }
  };

  const inputClass = "w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-white text-gray-900 placeholder-gray-400 transition-all outline-none shadow-sm";

  const OnboardingFlow = () => {
    const [step, setStep] = useState(0);
    const steps = [
      {
        title: "Stop Chasing.",
        subtitle: "Start Collecting.",
        description: "Unpaid invoices are the silent killer of small businesses. Debt Chaser is your automated recovery partner.",
        icon: DollarSign,
        color: "blue"
      },
      {
        title: "Smart Copy.",
        subtitle: "One-Tap Reminders.",
        description: "Generate professional WhatsApp reminders in seconds. Just copy, paste, and get paid.",
        icon: MessageSquare,
        color: "emerald"
      },
      {
        title: "Live Insights.",
        subtitle: "Know Your Cash.",
        description: "See exactly who owes you, how long they've been dodging, and your total recovery rate.",
        icon: TrendingUp,
        color: "purple"
      }
    ];

    const currentStep = steps[step];
    const isLastStep = step === steps.length - 1;

    return (
      <div className="fixed inset-0 bg-slate-950 z-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-[40px] w-full max-w-md overflow-hidden shadow-2xl relative">
          <div className="h-1.5 w-full flex gap-1 px-10 pt-10">
            {steps.map((_, i) => (
              <div key={i} className={`h-1 flex-1 rounded-full transition-all duration-700 ${i <= step ? 'bg-blue-600' : 'bg-gray-100'}`} />
            ))}
          </div>
          <div className="p-12 text-center">
            <div className={`inline-flex items-center justify-center w-28 h-28 rounded-[32px] mb-10 shadow-xl ${
              currentStep.color === 'blue' ? 'bg-blue-50 text-blue-600' :
              currentStep.color === 'emerald' ? 'bg-emerald-50 text-emerald-600' :
              'bg-purple-50 text-purple-600'
            }`}>
              <currentStep.icon className="w-14 h-14" />
            </div>
            <h2 className="text-4xl font-black text-slate-900 mb-2 leading-tight tracking-tight">{currentStep.title}</h2>
            <p className="text-blue-600 font-bold mb-8 uppercase tracking-widest text-xs">{currentStep.subtitle}</p>
            <p className="text-slate-500 leading-relaxed mb-12 font-medium">{currentStep.description}</p>
            <button
              onClick={async () => {
                if (isLastStep) {
                  await (window as any).storage.set('onboarding_complete', 'true');
                  setHasSeenOnboarding(true);
                } else {
                  setStep(step + 1);
                }
              }}
              className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg active:scale-95 transition-all shadow-2xl"
            >
              {isLastStep ? "Launch Dashboard" : "Next Step"}
            </button>
          </div>
        </div>
      </div>
    );
  };

  const SettingsModal = () => {
    return (
      <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[60] flex items-center justify-center p-4">
        <div className="bg-gray-50 rounded-[36px] w-full max-w-lg overflow-hidden shadow-2xl flex flex-col max-h-[85vh] border border-white/20">
          <div className="px-8 py-8 bg-white border-b flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="bg-blue-600 p-2.5 rounded-2xl text-white shadow-lg">
                <Settings2 className="w-6 h-6" />
              </div>
              <h3 className="font-black text-2xl text-slate-900">Settings</h3>
            </div>
            <button onClick={() => setShowSettings(false)} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
              <X className="w-7 h-7 text-gray-400" />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-8 space-y-10">
            <section className="space-y-5">
              <h4 className="flex items-center gap-2 text-slate-400 font-black text-[11px] uppercase tracking-[0.2em] px-1">
                <Building className="w-4 h-4" />
                Profile
              </h4>
              <div className="bg-white rounded-3xl p-6 border border-gray-200 space-y-5 shadow-sm">
                <div>
                  <label className="block text-xs font-black text-slate-500 mb-2 uppercase tracking-wider">Business Name</label>
                  <input type="text" value={settings.businessName} onChange={e => saveSettings({...settings, businessName: e.target.value})} className={inputClass} />
                </div>
              </div>
            </section>

            <section className="space-y-5">
              <h4 className="flex items-center gap-2 text-slate-400 font-black text-[11px] uppercase tracking-[0.2em] px-1">
                <Globe className="w-4 h-4" />
                Localization
              </h4>
              <div className="bg-white rounded-3xl p-6 border border-gray-200 shadow-sm">
                <label className="block text-xs font-black text-slate-500 mb-2 uppercase tracking-wider">Currency</label>
                <select value={settings.currency} onChange={e => saveSettings({...settings, currency: e.target.value})} className={inputClass}>
                  <option value="R">R (ZAR)</option>
                  <option value="$">$ (USD)</option>
                  <option value="£">£ (GBP)</option>
                  <option value="€">€ (EUR)</option>
                </select>
              </div>
            </section>

            <section className="space-y-5">
              <h4 className="flex items-center gap-2 text-slate-400 font-black text-[11px] uppercase tracking-[0.2em] px-1">
                <Shield className="w-4 h-4" />
                Security & Data
              </h4>
              <div className="bg-white rounded-3xl border border-gray-200 overflow-hidden shadow-sm">
                <button onClick={exportToCSV} className="w-full flex items-center justify-between p-5 hover:bg-gray-50 border-b transition-colors group">
                  <span className="flex items-center gap-3 font-bold text-slate-700">
                    <Download className="w-5 h-5 text-slate-300 group-hover:text-blue-500" /> Export Records (CSV)
                  </span>
                </button>
                <button 
                  onClick={handleReset}
                  disabled={isResetting}
                  className={`w-full flex items-center gap-3 p-5 transition-colors font-black ${isResetting ? 'bg-gray-100 text-gray-400' : 'hover:bg-red-50 text-red-600'}`}
                >
                  <Trash2 className={`w-5 h-5 ${isResetting ? 'animate-pulse' : ''}`} /> 
                  {isResetting ? 'Purging System...' : 'Reset Everything'}
                </button>
              </div>
            </section>
          </div>
        </div>
      </div>
    );
  };

  const UploadFlow = () => {
    const [formData, setFormData] = useState({ clientName: '', amount: '', dueDate: '', clientPhone: '', invoiceNumber: '' });
    return (
      <div className="fixed inset-0 bg-white z-[70] overflow-y-auto">
        <div className="bg-white border-b sticky top-0 z-10 px-6 py-6 max-w-2xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-5">
            <button onClick={() => setShowUpload(false)} className="p-3 bg-slate-50 hover:bg-slate-100 rounded-2xl text-slate-400 transition-colors">
              <ArrowLeft className="w-6 h-6" />
            </button>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">New Receivable</h1>
          </div>
        </div>
        <div className="max-w-2xl mx-auto px-8 py-10 space-y-10">
          <div className="grid gap-8">
            <div className="space-y-3">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">Client / Company Name</label>
              <input type="text" value={formData.clientName} onChange={(e) => setFormData({...formData, clientName: e.target.value})} placeholder="e.g. Acme Hardware" className={inputClass} />
            </div>
            <div className="grid grid-cols-2 gap-6">
              <div className="space-y-3">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">Amount Owed</label>
                <input type="number" value={formData.amount} onChange={(e) => setFormData({...formData, amount: e.target.value})} placeholder="0.00" className={inputClass} />
              </div>
              <div className="space-y-3">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">Due Date</label>
                <input type="date" value={formData.dueDate} onChange={(e) => setFormData({...formData, dueDate: e.target.value})} className={inputClass} />
              </div>
            </div>
            <div className="space-y-3">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest ml-1">WhatsApp Contact</label>
              <input type="tel" value={formData.clientPhone} onChange={(e) => setFormData({...formData, clientPhone: e.target.value})} placeholder="+..." className={inputClass} />
            </div>
          </div>
          <button 
            onClick={async () => { await addInvoice(formData); setShowUpload(false); }} 
            disabled={!formData.clientName || !formData.amount || !formData.dueDate}
            className="w-full bg-blue-600 text-white py-5 rounded-3xl font-black text-xl hover:bg-blue-700 disabled:bg-slate-100 disabled:text-slate-300 transition-all shadow-2xl active:scale-95"
          >
            Create Record
          </button>
        </div>
      </div>
    );
  };

  const WhatsAppMessage: React.FC<{ message: string; sent?: boolean }> = ({ message, sent = true }) => (
    <div className={`flex ${sent ? 'justify-end' : 'justify-start'} mb-4`}>
      <div className="max-w-[95%] rounded-3xl px-5 py-4 shadow-sm bg-[#DCF8C6] text-slate-900 border border-emerald-100">
        <p className="text-[14px] leading-relaxed whitespace-pre-wrap font-medium">{message}</p>
        <div className="flex items-center justify-end gap-1.5 mt-2 opacity-40">
          <span className="text-[10px] font-bold uppercase">
            {new Date().toLocaleTimeString('en-ZA', { hour: '2-digit', minute: '2-digit' })}
          </span>
          {sent && <CheckCheck className="w-3.5 h-3.5" />}
        </div>
      </div>
    </div>
  );

  const InvoiceDetail = () => {
    const invoice = invoices.find(inv => inv.id === selectedInvoiceId);
    if (!invoice) return null;
    const days = getDaysOverdue(invoice.dueDate);

    return (
      <div className="fixed inset-0 bg-slate-50 z-[55] overflow-y-auto pb-40">
        <div className="bg-white border-b sticky top-0 z-10 px-6 py-6">
          <div className="max-w-2xl mx-auto flex items-center justify-between">
            <button onClick={() => setSelectedInvoiceId(null)} className="p-3 bg-slate-50 hover:bg-slate-100 rounded-2xl text-slate-400 transition-colors">
              <ArrowLeft className="w-6 h-6" />
            </button>
            <h1 className="text-xl font-black text-slate-900 truncate max-w-[200px]">{invoice.clientName}</h1>
            <div className="w-12 h-12" />
          </div>
        </div>

        <div className="max-w-2xl mx-auto px-6 py-8 space-y-8">
          <div className="bg-white rounded-[40px] border border-gray-200 p-10 shadow-sm text-center">
            <span className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border-2 ${getStatusColor(invoice.status)}`}>
              {invoice.status === 'overdue' ? `🚨 ${days}D OVERDUE` : invoice.status}
            </span>
            <p className="text-6xl font-black text-slate-900 mt-6 tracking-tighter">{settings.currency}{invoice.amount.toLocaleString()}</p>
            <p className="text-slate-400 font-bold uppercase tracking-widest text-[9px] mt-2">Expected by {new Date(invoice.dueDate).toLocaleDateString('en-ZA', { month: 'long', day: 'numeric', year: 'numeric' })}</p>
          </div>

          <div className="space-y-5">
            <div className="flex items-center justify-between px-1">
               <h2 className="font-black text-slate-900 uppercase tracking-widest text-[10px] flex items-center gap-3">
                <History className="w-4 h-4 text-blue-500" />
                Communication Logs
              </h2>
              <button 
                onClick={() => setShowDeleteConfirm(true)}
                className="text-red-500 text-[10px] font-black uppercase tracking-widest flex items-center gap-1.5 hover:bg-red-50 px-3 py-1.5 rounded-xl transition-colors"
              >
                <Trash2 className="w-4 h-4" /> Purge Entry
              </button>
            </div>
            <div className="bg-white rounded-[32px] border border-gray-200 p-8 shadow-sm">
              {invoice.messages.length === 0 ? (
                <div className="text-center py-10 opacity-30 italic font-medium flex flex-col items-center gap-4">
                  <div className="p-4 bg-slate-50 rounded-full"><Clock className="w-6 h-6 text-slate-300" /></div>
                  <span className="text-sm">No reminders logged yet.</span>
                </div>
              ) : (
                invoice.messages.map((msg, idx) => (
                  <div key={idx} className="mb-6 last:mb-0">
                    <div className="text-[9px] font-black text-slate-300 uppercase tracking-widest text-center mb-3">
                      {new Date(msg.date).toLocaleDateString('en-ZA', { day: '2-digit', month: 'short' })}
                    </div>
                    <WhatsAppMessage message={formatMessage(messageTemplates[msg.type]?.example || "", invoice)} />
                  </div>
                ))
              )}
            </div>
          </div>
        </div>

        {invoice.status !== 'paid' && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 w-full max-w-2xl px-6 flex gap-4">
            <button 
              onClick={() => setShowSendConfirm(true)} 
              className="flex-[2] py-5 bg-[#25D366] text-white rounded-2xl font-black text-lg shadow-xl active:scale-95 flex items-center justify-center gap-3 hover:bg-[#20bd5c] transition-colors"
            >
              <Copy className="w-6 h-6" /> Copy Reminder
            </button>
            <button 
              onClick={() => setShowPaymentLog(true)} 
              className="flex-1 bg-white text-slate-900 border-4 border-slate-900 py-5 rounded-2xl font-black active:scale-95 hover:bg-slate-50 transition-colors"
            >
              Settled
            </button>
          </div>
        )}
      </div>
    );
  };

  if (loading) return null;
  if (!hasSeenOnboarding) return <OnboardingFlow />;

  return (
    <div className="min-h-screen bg-slate-50 pb-40">
      <header className="bg-white border-b sticky top-0 z-10 px-6 py-6">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="bg-slate-900 text-white p-2.5 rounded-2xl shadow-xl">
              <Zap className="w-6 h-6 fill-current" />
            </div>
            <div>
              <h1 className="text-2xl font-black text-slate-900 tracking-tighter leading-none uppercase">DEBT CHASER</h1>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mt-1 truncate max-w-[120px]">{settings.businessName}</p>
            </div>
          </div>
          <button onClick={() => setShowSettings(true)} className="p-3 bg-slate-50 hover:bg-slate-100 rounded-2xl transition-all">
            <SettingsIcon className="w-7 h-7 text-slate-400" />
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6 py-10 space-y-10">
        {invoices.length > 0 && (
          <div className="bg-slate-900 rounded-[48px] p-10 text-white shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-10 opacity-[0.03]"><TrendingUp className="w-64 h-64" /></div>
            <div className="relative z-10 grid md:grid-cols-2 gap-12 items-center">
              <div>
                <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.3em] mb-2">Total Recovered</p>
                <p className="text-6xl font-black tracking-tighter">{settings.currency}{analytics.totalRecovered.toLocaleString()}</p>
                <div className="mt-6 flex items-center gap-3">
                  <div className="bg-emerald-500/10 text-emerald-400 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border border-emerald-500/10">
                    {analytics.successRate}% Success
                  </div>
                  {analytics.averageDaysToPayment !== 0 && (
                    <div className="text-slate-500 text-[10px] font-bold uppercase tracking-widest">
                      ~{analytics.averageDaysToPayment} Days to Pay
                    </div>
                  )}
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="bg-white/5 border border-white/10 p-6 rounded-[32px] hover:bg-white/[0.08] transition-colors">
                  <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest mb-1">Pending</p>
                  <p className="text-2xl font-black">{settings.currency}{analytics.totalOutstanding.toLocaleString()}</p>
                </div>
                <div className="bg-red-500/5 border border-red-500/10 p-6 rounded-[32px] hover:bg-red-500/[0.08] transition-colors">
                  <p className="text-red-400 text-[9px] font-black uppercase tracking-widest mb-1">Overdue</p>
                  <p className="text-2xl font-black text-red-100">{settings.currency}{analytics.overdueAmount.toLocaleString()}</p>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="space-y-6">
          <div className="flex items-center justify-between px-3">
            <h2 className="font-black text-slate-900 uppercase tracking-[0.3em] text-[10px] flex items-center gap-3">
              <History className="w-4 h-4 text-slate-400" />
              Active Receivables
            </h2>
          </div>

          {invoices.length === 0 ? (
            <div className="bg-white rounded-[48px] border-4 border-dashed border-gray-100 p-24 text-center">
              <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-8">
                <FileText className="w-8 h-8 text-slate-200" />
              </div>
              <h3 className="text-2xl font-black text-slate-900 mb-3">Your Book is Clear</h3>
              <p className="text-slate-400 font-bold uppercase tracking-widest text-[9px] mb-12 max-w-xs mx-auto leading-relaxed">No unpaid invoices found. Use the button below to track a new debt.</p>
              <button onClick={() => setShowUpload(true)} className="bg-blue-600 text-white px-14 py-5 rounded-[24px] font-black shadow-xl active:scale-95 transition-all hover:bg-blue-700">
                Add Entry
              </button>
            </div>
          ) : (
            <div className="grid gap-4">
              {invoices.sort((a,b) => b.id - a.id).map(invoice => (
                <button 
                  key={invoice.id} 
                  onClick={() => setSelectedInvoiceId(invoice.id)} 
                  className="w-full bg-white rounded-[32px] border border-gray-100 p-8 text-left hover:border-blue-300 transition-all flex items-center gap-6 active:scale-[0.98] shadow-sm group"
                >
                  <div className={`w-16 h-16 rounded-[24px] flex items-center justify-center font-black text-2xl transition-transform group-hover:scale-105 ${
                    invoice.status === 'paid' ? 'bg-emerald-50 text-emerald-600' : 
                    invoice.status === 'overdue' ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'
                  }`}>
                    {invoice.clientName.charAt(0)}
                  </div>
                  <div className="flex-1 truncate">
                    <p className="font-black text-xl text-slate-900 tracking-tight truncate">{invoice.clientName}</p>
                    <div className="flex items-center gap-3 mt-2">
                      <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded border-2 ${getStatusColor(invoice.status)}`}>
                        {invoice.status}
                      </span>
                      <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                        <Calendar className="w-3 h-3" />
                        {new Date(invoice.dueDate).toLocaleDateString('en-ZA')}
                      </span>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="font-black text-xl text-slate-900 tracking-tighter">{settings.currency}{invoice.amount.toLocaleString()}</p>
                    <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest mt-1">
                      {invoice.remindersSent} Reminders
                    </p>
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>
      </main>

      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 w-full max-w-lg px-8">
        <button 
          onClick={() => setShowUpload(true)} 
          className="w-full bg-slate-900 text-white py-6 rounded-[30px] font-black text-xl flex items-center justify-center gap-4 shadow-3xl active:scale-95 border-4 border-white transition-all hover:bg-slate-800"
        >
          <Plus className="w-7 h-7" />
          New Invoice Record
        </button>
      </div>

      {showSettings && <SettingsModal />}
      {showUpload && <UploadFlow />}
      {selectedInvoiceId && <InvoiceDetail />}

      {/* CUSTOM DELETE CONFIRMATION MODAL */}
      {showDeleteConfirm && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[100] flex items-center justify-center p-6">
          <div className="bg-white rounded-[40px] w-full max-w-sm p-10 shadow-2xl text-center border border-white/20">
            <div className="w-24 h-24 bg-red-50 text-red-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 animate-pulse shadow-inner">
              <AlertCircle className="w-12 h-12" />
            </div>
            <h3 className="font-black text-3xl text-slate-900 mb-2 leading-tight">Delete Entry?</h3>
            <p className="text-slate-400 mb-10 font-bold uppercase tracking-widest text-[9px] leading-relaxed">This record will be permanently purged from your records.</p>
            <div className="flex flex-col gap-3">
              <button 
                onClick={async () => { await deleteInvoice(selectedInvoiceId!); }} 
                className="w-full py-5 bg-red-600 text-white rounded-[24px] font-black text-lg shadow-xl active:scale-95 hover:bg-red-700 transition-colors"
              >
                Delete Record
              </button>
              <button onClick={() => setShowDeleteConfirm(false)} className="w-full py-4 text-slate-400 font-black text-xs uppercase tracking-widest">Keep Entry</button>
            </div>
          </div>
        </div>
      )}

      {showSendConfirm && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[100] flex items-end sm:items-center justify-center p-6">
          <div className="bg-white rounded-[40px] w-full max-w-lg p-10 shadow-2xl border border-white/20">
            <h3 className="font-black text-3xl text-slate-900 mb-8 flex items-center gap-4">
              <BellRing className="w-8 h-8 text-emerald-500" />
              Copy Text
            </h3>
            <div className="bg-[#ECE5DD] rounded-[32px] p-8 mb-10 border-2 border-emerald-50 relative overflow-hidden">
               <div className="absolute top-0 right-0 p-3 opacity-10"><MessageSquare className="w-12 h-12" /></div>
              <WhatsAppMessage message={formatMessage(messageTemplates[settings.messageStyle]?.example || messageTemplates.friendly.example, invoices.find(i => i.id === selectedInvoiceId)!)} />
            </div>
            <div className="flex gap-4">
              <button onClick={() => setShowSendConfirm(false)} className="flex-1 py-5 font-black text-slate-400 uppercase text-[10px] tracking-widest">Cancel</button>
              <button 
                onClick={async () => { 
                  const inv = invoices.find(i => i.id === selectedInvoiceId)!;
                  const text = formatMessage(messageTemplates[settings.messageStyle]?.example || messageTemplates.friendly.example, inv);
                  await copyToClipboard(text);
                  await recordReminderSent(selectedInvoiceId, settings.messageStyle);
                  setShowSendConfirm(false);
                }} 
                className="flex-[2] py-5 bg-slate-900 text-white rounded-2xl font-black text-lg active:scale-95 shadow-xl"
              >
                Copy & Log Sent
              </button>
            </div>
          </div>
        </div>
      )}

      {showPaymentLog && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[100] flex items-center justify-center p-6">
          <div className="bg-white rounded-[40px] w-full max-w-sm p-10 shadow-2xl text-center border border-white/20">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 shadow-inner">
              <CheckCircle className="w-12 h-12" />
            </div>
            <h3 className="font-black text-3xl text-slate-900 mb-2 leading-tight">Mark Paid?</h3>
            <p className="text-slate-400 mb-10 font-bold uppercase tracking-widest text-[9px]">Confirm payment has been received in full.</p>
            <div className="flex flex-col gap-3">
              <button 
                onClick={async () => { await markAsPaid(selectedInvoiceId!); setShowPaymentLog(false); }} 
                className="w-full py-5 bg-emerald-600 text-white rounded-[24px] font-black text-lg shadow-xl active:scale-95 hover:bg-emerald-700"
              >
                Yes, It's Settled
              </button>
              <button onClick={() => setShowPaymentLog(false)} className="w-full py-4 text-slate-400 font-black text-xs uppercase tracking-widest">Not Yet</button>
            </div>
          </div>
        </div>
      )}

      {copySuccess && (
        <div className="fixed bottom-32 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-8 py-4 rounded-full font-black text-xs shadow-3xl z-[200] animate-bounce uppercase tracking-widest flex items-center gap-3">
          <CheckCheck className="w-4 h-4 text-emerald-400" />
          Copied
        </div>
      )}
    </div>
  );
}
